window.BIBLE["Zechariah"] = {"1":{"chapter":"1","title":"TURN YE UNTO ME — VISION OF THE HORSES","verses":{"1":{"text":"In the eighth month, in the second year of Darius, came the word of the LORD unto Zechariah, the son of Berechiah, the son of Iddo the prophet, saying,","ref":"Zechariah 1:1","synthesized":"In the eighth month of the second year of Darius, the word of the LORD came to the prophet Zechariah son of Berechiah, the son of Iddo, saying:","sources":{"KJV":{"text":"In the eighth month, in the second year of Darius, came the word of the LORD unto Zechariah, the son of Berechiah, the son of Iddo the prophet, saying,"},"BSB":{"text":"In the eighth month of the second year of Darius, the word of the LORD came to the prophet Zechariah son of Berechiah, the son of Iddo, saying:"}},"definableWords":["year","word","LORD","prophet","son","Son"],"peopleInVerse":[]},"2":{"text":"The LORD hath been sore displeased with your fathers.","ref":"Zechariah 1:2","synthesized":"“The LORD was very angry with your fathers.","sources":{"KJV":{"text":"The LORD hath been sore displeased with your fathers."},"BSB":{"text":"“The LORD was very angry with your fathers."}},"definableWords":["LORD","fathers"],"peopleInVerse":[]},"3":{"text":"Therefore say thou unto them, Thus saith the LORD of hosts; Turn ye unto me, saith the LORD of hosts, and I will turn unto you, saith the LORD of hosts.","ref":"Zechariah 1:3","synthesized":"So tell the people that this is what the LORD of Hosts says: ‘Return to Me, declares the LORD of Hosts, and I will return to you, says the LORD of Hosts.’","sources":{"KJV":{"text":"Therefore say thou unto them, Thus saith the LORD of hosts; Turn ye unto me, saith the LORD of hosts, and I will turn unto you, saith the LORD of hosts."},"BSB":{"text":"So tell the people that this is what the LORD of Hosts says: ‘Return to Me, declares the LORD of Hosts, and I will return to you, says the LORD of Hosts.’"}},"definableWords":["people","LORD","Lord"],"peopleInVerse":[]},"4":{"text":"Be ye not as your fathers, unto whom the former prophets have cried, saying, Thus saith the LORD of hosts; Turn ye now from your evil ways, and from your evil doings: but they did not hear, nor hearken unto me, saith the LORD.","ref":"Zechariah 1:4","synthesized":"Do not be like your fathers, to whom the former prophets proclaimed that this is what the LORD of Hosts says: ‘Turn now from your evil ways and deeds.’ But they did not listen or pay attention to Me, declares the LORD.","sources":{"KJV":{"text":"Be ye not as your fathers, unto whom the former prophets have cried, saying, Thus saith the LORD of hosts; Turn ye now from your evil ways, and from your evil doings: but they did not hear, nor hearken unto me, saith the LORD."},"BSB":{"text":"Do not be like your fathers, to whom the former prophets proclaimed that this is what the LORD of Hosts says: ‘Turn now from your evil ways and deeds.’ But they did not listen or pay attention to Me, declares the LORD."}},"definableWords":["fathers","LORD","evil","or","Lord"],"peopleInVerse":[]},"5":{"text":"Your fathers, where are they? and the prophets, do they live for ever?","ref":"Zechariah 1:5","synthesized":"Where are your fathers now? And the prophets, do they live forever?","sources":{"KJV":{"text":"Your fathers, where are they? and the prophets, do they live for ever?"},"BSB":{"text":"Where are your fathers now? And the prophets, do they live forever?"}},"definableWords":["fathers","live"],"peopleInVerse":[]},"6":{"text":"But my words and my statutes, which I commanded my servants the prophets, did they not take hold of your fathers? and they returned and said, Like as the LORD of hosts thought to do unto us, according to our ways, and according to our doings, so hath he dealt with us.","ref":"Zechariah 1:6","synthesized":"But did not My words and My statutes, which I commanded My servants the prophets, overtake your fathers? They repented and said, ‘Just as the LORD of Hosts purposed to do to us according to our ways and deeds, so He has done to us.’”","sources":{"KJV":{"text":"But my words and my statutes, which I commanded my servants the prophets, did they not take hold of your fathers? and they returned and said, Like as the LORD of hosts thought to do unto us, according to our ways, and according to our doings, so hath he dealt with us."},"BSB":{"text":"But did not My words and My statutes, which I commanded My servants the prophets, overtake your fathers? They repented and said, ‘Just as the LORD of Hosts purposed to do to us according to our ways and deeds, so He has done to us.’”"}},"definableWords":["servants","fathers","LORD"],"peopleInVerse":[]},"7":{"text":"Upon the four and twentieth day of the eleventh month, which is the month Sebat, in the second year of Darius, came the word of the LORD unto Zechariah, the son of Berechiah, the son of Iddo the prophet, saying,","ref":"Zechariah 1:7","synthesized":"On the twenty-fourth day of the eleventh month, the month of Shebat, in the second year of Darius, the word of the LORD came to the prophet Zechariah son of Berechiah, the son of Iddo.","sources":{"KJV":{"text":"Upon the four and twentieth day of the eleventh month, which is the month Sebat, in the second year of Darius, came the word of the LORD unto Zechariah, the son of Berechiah, the son of Iddo the prophet, saying,"},"BSB":{"text":"On the twenty-fourth day of the eleventh month, the month of Shebat, in the second year of Darius, the word of the LORD came to the prophet Zechariah son of Berechiah, the son of Iddo."}},"definableWords":["day","year","word","LORD","prophet","son","Son"],"peopleInVerse":[]},"8":{"text":"I saw by night, and behold a man riding upon a red horse, and he stood among the myrtle trees that were in the bottom; and behind him were there red horses, speckled, and white.","ref":"Zechariah 1:8","synthesized":"I looked out into the night and saw a man riding on a red horse. He was standing among the myrtle trees in the hollow, and behind him were red, sorrel, and white horses.","sources":{"KJV":{"text":"I saw by night, and behold a man riding upon a red horse, and he stood among the myrtle trees that were in the bottom; and behind him were there red horses, speckled, and white."},"BSB":{"text":"I looked out into the night and saw a man riding on a red horse. He was standing among the myrtle trees in the hollow, and behind him were red, sorrel, and white horses."}},"definableWords":["night","saw","man","trees"],"peopleInVerse":[]},"9":{"text":"Then said I, O my lord, what are these? And the angel that talked with me said unto me, I will shew thee what these be.","ref":"Zechariah 1:9","synthesized":"“What are these, my lord?” I asked. And the angel who was speaking with me replied, “I will show you what they are.”","sources":{"KJV":{"text":"Then said I, O my lord, what are these? And the angel that talked with me said unto me, I will shew thee what these be."},"BSB":{"text":"“What are these, my lord?” I asked. And the angel who was speaking with me replied, “I will show you what they are.”"}},"definableWords":["Lord","angel"],"peopleInVerse":[]},"10":{"text":"And the man that stood among the myrtle trees answered and said, These are they whom the LORD hath sent to walk to and fro through the earth.","ref":"Zechariah 1:10","synthesized":"Then the man standing among the myrtle trees explained, “They are the ones the LORD has sent to patrol the earth.”","sources":{"KJV":{"text":"And the man that stood among the myrtle trees answered and said, These are they whom the LORD hath sent to walk to and fro through the earth."},"BSB":{"text":"Then the man standing among the myrtle trees explained, “They are the ones the LORD has sent to patrol the earth.”"}},"definableWords":["man","trees","LORD","earth"],"peopleInVerse":[]},"11":{"text":"And they answered the angel of the LORD that stood among the myrtle trees, and said, We have walked to and fro through the earth, and, behold, all the earth sitteth still, and is at rest.","ref":"Zechariah 1:11","synthesized":"And the riders answered the angel of the LORD who was standing among the myrtle trees, “We have patrolled the earth, and behold, all the earth is at rest and tranquil.”","sources":{"KJV":{"text":"And they answered the angel of the LORD that stood among the myrtle trees, and said, We have walked to and fro through the earth, and, behold, all the earth sitteth still, and is at rest."},"BSB":{"text":"And the riders answered the angel of the LORD who was standing among the myrtle trees, “We have patrolled the earth, and behold, all the earth is at rest and tranquil.”"}},"definableWords":["angel","LORD","trees","earth","rest"],"peopleInVerse":[]},"12":{"text":"Then the angel of the LORD answered and said, O LORD of hosts, how long wilt thou not have mercy on Jerusalem and on the cities of Judah, against which thou hast had indignation these threescore and ten years?","ref":"Zechariah 1:12","synthesized":"Then the angel of the LORD said, “How long, O LORD of Hosts, will You withhold mercy from Jerusalem and the cities of Judah, with which You have been angry these seventy years?”","sources":{"KJV":{"text":"Then the angel of the LORD answered and said, O LORD of hosts, how long wilt thou not have mercy on Jerusalem and on the cities of Judah, against which thou hast had indignation these threescore and ten years?"},"BSB":{"text":"Then the angel of the LORD said, “How long, O LORD of Hosts, will You withhold mercy from Jerusalem and the cities of Judah, with which You have been angry these seventy years?”"}},"definableWords":["angel","LORD","Lord","mercy","Jerusalem","Judah","years"],"peopleInVerse":[]},"13":{"text":"And the LORD answered the angel that talked with me with good words and comfortable words.","ref":"Zechariah 1:13","synthesized":"So the LORD spoke kind and comforting words to the angel who was speaking with me.","sources":{"KJV":{"text":"And the LORD answered the angel that talked with me with good words and comfortable words."},"BSB":{"text":"So the LORD spoke kind and comforting words to the angel who was speaking with me."}},"definableWords":["LORD","angel"],"peopleInVerse":[]},"14":{"text":"So the angel that communed with me said unto me, Cry thou, saying, Thus saith the LORD of hosts; I am jealous for Jerusalem and for Zion with a great jealousy.","ref":"Zechariah 1:14","synthesized":"Then the angel who was speaking with me said, “Proclaim this word: This is what the LORD of Hosts says: ‘I am very jealous for Jerusalem and Zion,","sources":{"KJV":{"text":"So the angel that communed with me said unto me, Cry thou, saying, Thus saith the LORD of hosts; I am jealous for Jerusalem and for Zion with a great jealousy."},"BSB":{"text":"Then the angel who was speaking with me said, “Proclaim this word: This is what the LORD of Hosts says: ‘I am very jealous for Jerusalem and Zion,"}},"definableWords":["angel","word","LORD","Jerusalem","Zion"],"peopleInVerse":[]},"15":{"text":"And I am very sore displeased with the heathen that are at ease: for I was but a little displeased, and they helped forward the affliction.","ref":"Zechariah 1:15","synthesized":"but I am fiercely angry with the nations that are at ease. For I was a little angry, but they have added to the calamity.’","sources":{"KJV":{"text":"And I am very sore displeased with the heathen that are at ease: for I was but a little displeased, and they helped forward the affliction."},"BSB":{"text":"but I am fiercely angry with the nations that are at ease. For I was a little angry, but they have added to the calamity.’"}},"definableWords":["nations"],"peopleInVerse":[]},"16":{"text":"Therefore thus saith the LORD; I am returned to Jerusalem with mercies: my house shall be built in it, saith the LORD of hosts, and a line shall be stretched forth upon Jerusalem.","ref":"Zechariah 1:16","synthesized":"Therefore this is what the LORD says: ‘I will return to Jerusalem with mercy, and there My house will be rebuilt, declares the LORD of Hosts, and a measuring line will be stretched out over Jerusalem.’","sources":{"KJV":{"text":"Therefore thus saith the LORD; I am returned to Jerusalem with mercies: my house shall be built in it, saith the LORD of hosts, and a line shall be stretched forth upon Jerusalem."},"BSB":{"text":"Therefore this is what the LORD says: ‘I will return to Jerusalem with mercy, and there My house will be rebuilt, declares the LORD of Hosts, and a measuring line will be stretched out over Jerusalem.’"}},"definableWords":["LORD","Jerusalem","mercy","house","Lord"],"peopleInVerse":[]},"17":{"text":"Cry yet, saying, Thus saith the LORD of hosts; My cities through prosperity shall yet be spread abroad; and the LORD shall yet comfort Zion, and shall yet choose Jerusalem.","ref":"Zechariah 1:17","synthesized":"Proclaim further that this is what the LORD of Hosts says: ‘My cities will again overflow with prosperity; the LORD will again comfort Zion and choose Jerusalem.’”","sources":{"KJV":{"text":"Cry yet, saying, Thus saith the LORD of hosts; My cities through prosperity shall yet be spread abroad; and the LORD shall yet comfort Zion, and shall yet choose Jerusalem."},"BSB":{"text":"Proclaim further that this is what the LORD of Hosts says: ‘My cities will again overflow with prosperity; the LORD will again comfort Zion and choose Jerusalem.’”"}},"definableWords":["LORD","Lord","Zion","Jerusalem"],"peopleInVerse":[]},"18":{"text":"Then lifted I up mine eyes, and saw, and behold four horns.","ref":"Zechariah 1:18","synthesized":"Then I looked up and saw four horns.","sources":{"KJV":{"text":"Then lifted I up mine eyes, and saw, and behold four horns."},"BSB":{"text":"Then I looked up and saw four horns."}},"definableWords":["saw"],"peopleInVerse":[]},"19":{"text":"And I said unto the angel that talked with me, What be these? And he answered me, These are the horns which have scattered Judah, Israel, and Jerusalem.","ref":"Zechariah 1:19","synthesized":"So I asked the angel who was speaking with me, “What are these?” And he told me, “These are the horns that have scattered Judah, Israel, and Jerusalem.”","sources":{"KJV":{"text":"And I said unto the angel that talked with me, What be these? And he answered me, These are the horns which have scattered Judah, Israel, and Jerusalem."},"BSB":{"text":"So I asked the angel who was speaking with me, “What are these?” And he told me, “These are the horns that have scattered Judah, Israel, and Jerusalem.”"}},"definableWords":["angel","Judah","Israel","Jerusalem"],"peopleInVerse":[]},"20":{"text":"And the LORD shewed me four carpenters.","ref":"Zechariah 1:20","synthesized":"Then the LORD showed me four craftsmen.","sources":{"KJV":{"text":"And the LORD shewed me four carpenters."},"BSB":{"text":"Then the LORD showed me four craftsmen."}},"definableWords":["LORD"],"peopleInVerse":[]},"21":{"text":"Then said I, What come these to do? And he spake, saying, These are the horns which have scattered Judah, so that no man did lift up his head: but these are come to fray them, to cast out the horns of the Gentiles, which lifted up their horn over the land of Judah to scatter it.","ref":"Zechariah 1:21","synthesized":"“What are these coming to do?” I asked. And He replied, “These are the horns that scattered Judah so that no one could raise his head; but the craftsmen have come to terrify them and throw down these horns of the nations that have lifted up their horns against the land of Judah to scatter it.”","sources":{"KJV":{"text":"Then said I, What come these to do? And he spake, saying, These are the horns which have scattered Judah, so that no man did lift up his head: but these are come to fray them, to cast out the horns of the Gentiles, which lifted up their horn over the land of Judah to scatter it."},"BSB":{"text":"“What are these coming to do?” I asked. And He replied, “These are the horns that scattered Judah so that no one could raise his head; but the craftsmen have come to terrify them and throw down these horns of the nations that have lifted up their horns against the land of Judah to scatter it.”"}},"definableWords":["Judah","one","nations","land"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"THE MAN WITH THE MEASURING LINE","verses":{"1":{"text":"I lifted up mine eyes again, and looked, and behold a man with a measuring line in his hand.","ref":"Zechariah 2:1","synthesized":"Then I lifted up my eyes and saw a man with a measuring line in his hand.","sources":{"KJV":{"text":"I lifted up mine eyes again, and looked, and behold a man with a measuring line in his hand."},"BSB":{"text":"Then I lifted up my eyes and saw a man with a measuring line in his hand."}},"definableWords":["saw","man"],"peopleInVerse":[]},"2":{"text":"Then said I, Whither goest thou? And he said unto me, To measure Jerusalem, to see what is the breadth thereof, and what is the length thereof.","ref":"Zechariah 2:2","synthesized":"“Where are you going?” I asked. “To measure Jerusalem,” he replied, “and to determine its width and length.”","sources":{"KJV":{"text":"Then said I, Whither goest thou? And he said unto me, To measure Jerusalem, to see what is the breadth thereof, and what is the length thereof."},"BSB":{"text":"“Where are you going?” I asked. “To measure Jerusalem,” he replied, “and to determine its width and length.”"}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"3":{"text":"And, behold, the angel that talked with me went forth, and another angel went out to meet him,","ref":"Zechariah 2:3","synthesized":"Then the angel who was speaking with me went out, and another angel came out to meet him","sources":{"KJV":{"text":"And, behold, the angel that talked with me went forth, and another angel went out to meet him,"},"BSB":{"text":"Then the angel who was speaking with me went out, and another angel came out to meet him"}},"definableWords":["angel"],"peopleInVerse":[]},"4":{"text":"And said unto him, Run, speak to this young man, saying, Jerusalem shall be inhabited as towns without walls for the multitude of men and cattle therein:","ref":"Zechariah 2:4","synthesized":"and said to him, “Run and tell that young man: ‘Jerusalem will be a city without walls because of the multitude of men and livestock within it.","sources":{"KJV":{"text":"And said unto him, Run, speak to this young man, saying, Jerusalem shall be inhabited as towns without walls for the multitude of men and cattle therein:"},"BSB":{"text":"and said to him, “Run and tell that young man: ‘Jerusalem will be a city without walls because of the multitude of men and livestock within it."}},"definableWords":["run","man","Jerusalem","men"],"peopleInVerse":[]},"5":{"text":"For I, saith the LORD, will be unto her a wall of fire round about, and will be the glory in the midst of her.","ref":"Zechariah 2:5","synthesized":"For I will be a wall of fire around it, declares the LORD, and I will be the glory within it.’”","sources":{"KJV":{"text":"For I, saith the LORD, will be unto her a wall of fire round about, and will be the glory in the midst of her."},"BSB":{"text":"For I will be a wall of fire around it, declares the LORD, and I will be the glory within it.’”"}},"definableWords":["LORD","glory"],"peopleInVerse":[]},"6":{"text":"Ho, ho, come forth, and flee from the land of the north, saith the LORD: for I have spread you abroad as the four winds of the heaven, saith the LORD.","ref":"Zechariah 2:6","synthesized":"“Get up! Get up! Flee from the land of the north,” declares the LORD, “for I have scattered you like the four winds of heaven,” declares the LORD.","sources":{"KJV":{"text":"Ho, ho, come forth, and flee from the land of the north, saith the LORD: for I have spread you abroad as the four winds of the heaven, saith the LORD."},"BSB":{"text":"“Get up! Get up! Flee from the land of the north,” declares the LORD, “for I have scattered you like the four winds of heaven,” declares the LORD."}},"definableWords":["land","LORD","heaven","Lord"],"peopleInVerse":[]},"7":{"text":"Deliver thyself, O Zion, that dwellest with the daughter of Babylon.","ref":"Zechariah 2:7","synthesized":"“Get up, O Zion! Escape, you who dwell with the Daughter of Babylon!”","sources":{"KJV":{"text":"Deliver thyself, O Zion, that dwellest with the daughter of Babylon."},"BSB":{"text":"“Get up, O Zion! Escape, you who dwell with the Daughter of Babylon!”"}},"definableWords":["Zion","daughter","Babylon"],"peopleInVerse":[]},"8":{"text":"For thus saith the LORD of hosts; After the glory hath he sent me unto the nations which spoiled you: for he that toucheth you toucheth the apple of his eye.","ref":"Zechariah 2:8","synthesized":"For this is what the LORD of Hosts says: “After His Glory has sent Me against the nations that have plundered you—for whoever touches you touches the apple of His eye—","sources":{"KJV":{"text":"For thus saith the LORD of hosts; After the glory hath he sent me unto the nations which spoiled you: for he that toucheth you toucheth the apple of his eye."},"BSB":{"text":"For this is what the LORD of Hosts says: “After His Glory has sent Me against the nations that have plundered you—for whoever touches you touches the apple of His eye—"}},"definableWords":["LORD","glory","nations"],"peopleInVerse":[]},"9":{"text":"For, behold, I will shake mine hand upon them, and they shall be a spoil to their servants: and ye shall know that the LORD of hosts hath sent me.","ref":"Zechariah 2:9","synthesized":"I will surely wave My hand over them, so that they will become plunder for their own servants. Then you will know that the LORD of Hosts has sent Me.”","sources":{"KJV":{"text":"For, behold, I will shake mine hand upon them, and they shall be a spoil to their servants: and ye shall know that the LORD of hosts hath sent me."},"BSB":{"text":"I will surely wave My hand over them, so that they will become plunder for their own servants. Then you will know that the LORD of Hosts has sent Me.”"}},"definableWords":["servants","LORD"],"peopleInVerse":[]},"10":{"text":"Sing and rejoice, O daughter of Zion: for, lo, I come, and I will dwell in the midst of thee, saith the LORD.","ref":"Zechariah 2:10","synthesized":"“Shout for joy and be glad, O Daughter of Zion, for I am coming to dwell among you,” declares the LORD.","sources":{"KJV":{"text":"Sing and rejoice, O daughter of Zion: for, lo, I come, and I will dwell in the midst of thee, saith the LORD."},"BSB":{"text":"“Shout for joy and be glad, O Daughter of Zion, for I am coming to dwell among you,” declares the LORD."}},"definableWords":["joy","daughter","Zion","LORD"],"peopleInVerse":[]},"11":{"text":"And many nations shall be joined to the LORD in that day, and shall be my people: and I will dwell in the midst of thee, and thou shalt know that the LORD of hosts hath sent me unto thee.","ref":"Zechariah 2:11","synthesized":"“On that day many nations will join themselves to the LORD, and they will become My people. I will dwell among you, and you will know that the LORD of Hosts has sent Me to you.","sources":{"KJV":{"text":"And many nations shall be joined to the LORD in that day, and shall be my people: and I will dwell in the midst of thee, and thou shalt know that the LORD of hosts hath sent me unto thee."},"BSB":{"text":"“On that day many nations will join themselves to the LORD, and they will become My people. I will dwell among you, and you will know that the LORD of Hosts has sent Me to you."}},"definableWords":["day","nations","LORD","people","Lord"],"peopleInVerse":[]},"12":{"text":"And the LORD shall inherit Judah his portion in the holy land, and shall choose Jerusalem again.","ref":"Zechariah 2:12","synthesized":"And the LORD will take possession of Judah as His portion in the Holy Land, and He will once again choose Jerusalem.","sources":{"KJV":{"text":"And the LORD shall inherit Judah his portion in the holy land, and shall choose Jerusalem again."},"BSB":{"text":"And the LORD will take possession of Judah as His portion in the Holy Land, and He will once again choose Jerusalem."}},"definableWords":["LORD","Judah","holy","land","Jerusalem"],"peopleInVerse":[]},"13":{"text":"Be silent, O all flesh, before the LORD: for he is raised up out of his holy habitation.","ref":"Zechariah 2:13","synthesized":"Be silent before the LORD, all people, for He has roused Himself from His holy dwelling.”","sources":{"KJV":{"text":"Be silent, O all flesh, before the LORD: for he is raised up out of his holy habitation."},"BSB":{"text":"Be silent before the LORD, all people, for He has roused Himself from His holy dwelling.”"}},"definableWords":["LORD","people","holy"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"JOSHUA THE HIGH PRIEST","verses":{"1":{"text":"And he shewed me Joshua the high priest standing before the angel of the LORD, and Satan standing at his right hand to resist him.","ref":"Zechariah 3:1","synthesized":"Then the angel showed me Joshua the high priest standing before the angel of the LORD, with Satan standing at his right hand to accuse him.","sources":{"KJV":{"text":"And he shewed me Joshua the high priest standing before the angel of the LORD, and Satan standing at his right hand to resist him."},"BSB":{"text":"Then the angel showed me Joshua the high priest standing before the angel of the LORD, with Satan standing at his right hand to accuse him."}},"definableWords":["angel","priest","LORD","Satan"],"peopleInVerse":["Joshua"]},"2":{"text":"And the LORD said unto Satan, The LORD rebuke thee, O Satan; even the LORD that hath chosen Jerusalem rebuke thee: is not this a brand plucked out of the fire?","ref":"Zechariah 3:2","synthesized":"And the LORD said to Satan: “The LORD rebukes you, Satan! Indeed, the LORD, who has chosen Jerusalem, rebukes you! Is not this man a firebrand snatched from the fire?”","sources":{"KJV":{"text":"And the LORD said unto Satan, The LORD rebuke thee, O Satan; even the LORD that hath chosen Jerusalem rebuke thee: is not this a brand plucked out of the fire?"},"BSB":{"text":"And the LORD said to Satan: “The LORD rebukes you, Satan! Indeed, the LORD, who has chosen Jerusalem, rebukes you! Is not this man a firebrand snatched from the fire?”"}},"definableWords":["LORD","Satan","Lord","Jerusalem","man"],"peopleInVerse":[]},"3":{"text":"Now Joshua was clothed with filthy garments, and stood before the angel.","ref":"Zechariah 3:3","synthesized":"Now Joshua was dressed in filthy garments as he stood before the angel.","sources":{"KJV":{"text":"Now Joshua was clothed with filthy garments, and stood before the angel."},"BSB":{"text":"Now Joshua was dressed in filthy garments as he stood before the angel."}},"definableWords":["angel"],"peopleInVerse":["Joshua"]},"4":{"text":"And he answered and spake unto those that stood before him, saying, Take away the filthy garments from him. And unto him he said, Behold, I have caused thine iniquity to pass from thee, and I will clothe thee with change of raiment.","ref":"Zechariah 3:4","synthesized":"So the angel said to those standing before him, “Take off his filthy clothes!” Then he said to Joshua, “See, I have removed your iniquity, and I will clothe you with splendid robes.”","sources":{"KJV":{"text":"And he answered and spake unto those that stood before him, saying, Take away the filthy garments from him. And unto him he said, Behold, I have caused thine iniquity to pass from thee, and I will clothe thee with change of raiment."},"BSB":{"text":"So the angel said to those standing before him, “Take off his filthy clothes!” Then he said to Joshua, “See, I have removed your iniquity, and I will clothe you with splendid robes.”"}},"definableWords":["angel","see","iniquity"],"peopleInVerse":["Joshua"]},"5":{"text":"And I said, Let them set a fair mitre upon his head. So they set a fair mitre upon his head, and clothed him with garments. And the angel of the LORD stood by.","ref":"Zechariah 3:5","synthesized":"Then I said, “Let them put a clean turban on his head.” So a clean turban was placed on his head, and they clothed him, as the angel of the LORD stood by.","sources":{"KJV":{"text":"And I said, Let them set a fair mitre upon his head. So they set a fair mitre upon his head, and clothed him with garments. And the angel of the LORD stood by."},"BSB":{"text":"Then I said, “Let them put a clean turban on his head.” So a clean turban was placed on his head, and they clothed him, as the angel of the LORD stood by."}},"definableWords":["angel","LORD"],"peopleInVerse":[]},"6":{"text":"And the angel of the LORD protested unto Joshua, saying,","ref":"Zechariah 3:6","synthesized":"Then the angel of the LORD gave this charge to Joshua:","sources":{"KJV":{"text":"And the angel of the LORD protested unto Joshua, saying,"},"BSB":{"text":"Then the angel of the LORD gave this charge to Joshua:"}},"definableWords":["angel","LORD","charge"],"peopleInVerse":["Joshua"]},"7":{"text":"Thus saith the LORD of hosts; If thou wilt walk in my ways, and if thou wilt keep my charge, then thou shalt also judge my house, and shalt also keep my courts, and I will give thee places to walk among these that stand by.","ref":"Zechariah 3:7","synthesized":"“This is what the LORD of Hosts says: ‘If you walk in My ways and keep My instructions, then you will govern My house and will also have charge of My courts; and I will give you a place among these who are standing here.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; If thou wilt walk in my ways, and if thou wilt keep my charge, then thou shalt also judge my house, and shalt also keep my courts, and I will give thee places to walk among these that stand by."},"BSB":{"text":"“This is what the LORD of Hosts says: ‘If you walk in My ways and keep My instructions, then you will govern My house and will also have charge of My courts; and I will give you a place among these who are standing here."}},"definableWords":["LORD","walk","keep","house","charge"],"peopleInVerse":[]},"8":{"text":"Hear now, O Joshua the high priest, thou, and thy fellows that sit before thee: for they are men wondered at: for, behold, I will bring forth my servant the BRANCH.","ref":"Zechariah 3:8","synthesized":"Hear now, O high priest Joshua, you and your companions seated before you, who are indeed a sign. For behold, I am going to bring My servant, the Branch.","sources":{"KJV":{"text":"Hear now, O Joshua the high priest, thou, and thy fellows that sit before thee: for they are men wondered at: for, behold, I will bring forth my servant the BRANCH."},"BSB":{"text":"Hear now, O high priest Joshua, you and your companions seated before you, who are indeed a sign. For behold, I am going to bring My servant, the Branch."}},"definableWords":["hear","priest","servant"],"peopleInVerse":["Joshua"]},"9":{"text":"For behold the stone that I have laid before Joshua; upon one stone shall be seven eyes: behold, I will engrave the graving thereof, saith the LORD of hosts, and I will remove the iniquity of that land in one day.","ref":"Zechariah 3:9","synthesized":"See the stone I have set before Joshua; on that one stone are seven eyes. Behold, I will engrave on it an inscription, declares the LORD of Hosts, and I will remove the iniquity of this land in a single day.","sources":{"KJV":{"text":"For behold the stone that I have laid before Joshua; upon one stone shall be seven eyes: behold, I will engrave the graving thereof, saith the LORD of hosts, and I will remove the iniquity of that land in one day."},"BSB":{"text":"See the stone I have set before Joshua; on that one stone are seven eyes. Behold, I will engrave on it an inscription, declares the LORD of Hosts, and I will remove the iniquity of this land in a single day."}},"definableWords":["see","stone","one","LORD","iniquity","land","day"],"peopleInVerse":["Joshua"]},"10":{"text":"In that day, saith the LORD of hosts, shall ye call every man his neighbour under the vine and under the fig tree.","ref":"Zechariah 3:10","synthesized":"On that day, declares the LORD of Hosts, you will each invite your neighbor to sit under your own vine and fig tree.’”","sources":{"KJV":{"text":"In that day, saith the LORD of hosts, shall ye call every man his neighbour under the vine and under the fig tree."},"BSB":{"text":"On that day, declares the LORD of Hosts, you will each invite your neighbor to sit under your own vine and fig tree.’”"}},"definableWords":["day","LORD","tree"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"THE GOLDEN LAMPSTAND","verses":{"1":{"text":"And the angel that talked with me came again, and waked me, as a man that is wakened out of his sleep,","ref":"Zechariah 4:1","synthesized":"Then the angel who was speaking with me returned and woke me, as a man is awakened from his sleep.","sources":{"KJV":{"text":"And the angel that talked with me came again, and waked me, as a man that is wakened out of his sleep,"},"BSB":{"text":"Then the angel who was speaking with me returned and woke me, as a man is awakened from his sleep."}},"definableWords":["angel","man"],"peopleInVerse":[]},"2":{"text":"And said unto me, What seest thou? And I said, I have looked, and behold a candlestick all of gold, with a bowl upon the top of it, and his seven lamps thereon, and seven pipes to the seven lamps, which are upon the top thereof:","ref":"Zechariah 4:2","synthesized":"“What do you see?” he asked. “I see a solid gold lampstand,” I replied, “with a bowl at the top and seven lamps on it, with seven spouts to the lamps.","sources":{"KJV":{"text":"And said unto me, What seest thou? And I said, I have looked, and behold a candlestick all of gold, with a bowl upon the top of it, and his seven lamps thereon, and seven pipes to the seven lamps, which are upon the top thereof:"},"BSB":{"text":"“What do you see?” he asked. “I see a solid gold lampstand,” I replied, “with a bowl at the top and seven lamps on it, with seven spouts to the lamps."}},"definableWords":["see"],"peopleInVerse":[]},"3":{"text":"And two olive trees by it, one upon the right side of the bowl, and the other upon the left side thereof.","ref":"Zechariah 4:3","synthesized":"There are also two olive trees beside it, one on the right side of the bowl and the other on its left.”","sources":{"KJV":{"text":"And two olive trees by it, one upon the right side of the bowl, and the other upon the left side thereof."},"BSB":{"text":"There are also two olive trees beside it, one on the right side of the bowl and the other on its left.”"}},"definableWords":["trees","one"],"peopleInVerse":[]},"4":{"text":"So I answered and spake to the angel that talked with me, saying, What are these, my lord?","ref":"Zechariah 4:4","synthesized":"“What are these, my lord?” I asked the angel who was speaking with me.","sources":{"KJV":{"text":"So I answered and spake to the angel that talked with me, saying, What are these, my lord?"},"BSB":{"text":"“What are these, my lord?” I asked the angel who was speaking with me."}},"definableWords":["Lord","angel"],"peopleInVerse":[]},"5":{"text":"Then the angel that talked with me answered and said unto me, Knowest thou not what these be? And I said, No, my lord.","ref":"Zechariah 4:5","synthesized":"“Do you not know what they are?” replied the angel. “No, my lord,” I answered.","sources":{"KJV":{"text":"Then the angel that talked with me answered and said unto me, Knowest thou not what these be? And I said, No, my lord."},"BSB":{"text":"“Do you not know what they are?” replied the angel. “No, my lord,” I answered."}},"definableWords":["angel","Lord"],"peopleInVerse":[]},"6":{"text":"Then he answered and spake unto me, saying, This is the word of the LORD unto Zerubbabel, saying, Not by might, nor by power, but by my spirit, saith the LORD of hosts.","ref":"Zechariah 4:6","synthesized":"So he said to me, “This is the word of the LORD to Zerubbabel: Not by might nor by power, but by My Spirit, says the LORD of Hosts.","sources":{"KJV":{"text":"Then he answered and spake unto me, saying, This is the word of the LORD unto Zerubbabel, saying, Not by might, nor by power, but by my spirit, saith the LORD of hosts."},"BSB":{"text":"So he said to me, “This is the word of the LORD to Zerubbabel: Not by might nor by power, but by My Spirit, says the LORD of Hosts."}},"definableWords":["word","LORD","Spirit","Lord"],"peopleInVerse":[]},"7":{"text":"Who art thou, O great mountain? before Zerubbabel thou shalt become a plain: and he shall bring forth the headstone thereof with shoutings, crying, Grace, grace unto it.","ref":"Zechariah 4:7","synthesized":"What are you, O great mountain? Before Zerubbabel you will become a plain. Then he will bring forth the capstone accompanied by shouts of ‘Grace, grace to it!’”","sources":{"KJV":{"text":"Who art thou, O great mountain? before Zerubbabel thou shalt become a plain: and he shall bring forth the headstone thereof with shoutings, crying, Grace, grace unto it."},"BSB":{"text":"What are you, O great mountain? Before Zerubbabel you will become a plain. Then he will bring forth the capstone accompanied by shouts of ‘Grace, grace to it!’”"}},"definableWords":["great","grace"],"peopleInVerse":[]},"8":{"text":"Moreover the word of the LORD came unto me, saying,","ref":"Zechariah 4:8","synthesized":"Then the word of the LORD came to me, saying,","sources":{"KJV":{"text":"Moreover the word of the LORD came unto me, saying,"},"BSB":{"text":"Then the word of the LORD came to me, saying,"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"9":{"text":"The hands of Zerubbabel have laid the foundation of this house; his hands shall also finish it; and thou shalt know that the LORD of hosts hath sent me unto you.","ref":"Zechariah 4:9","synthesized":"“The hands of Zerubbabel have laid the foundation of this house, and his hands will complete it. Then you will know that the LORD of Hosts has sent me to you.","sources":{"KJV":{"text":"The hands of Zerubbabel have laid the foundation of this house; his hands shall also finish it; and thou shalt know that the LORD of hosts hath sent me unto you."},"BSB":{"text":"“The hands of Zerubbabel have laid the foundation of this house, and his hands will complete it. Then you will know that the LORD of Hosts has sent me to you."}},"definableWords":["house","LORD"],"peopleInVerse":[]},"10":{"text":"For who hath despised the day of small things? for they shall rejoice, and shall see the plummet in the hand of Zerubbabel with those seven; they are the eyes of the LORD, which run to and fro through the whole earth.","ref":"Zechariah 4:10","synthesized":"For who has despised the day of small things? But these seven eyes of the LORD, which scan the whole earth, will rejoice when they see the plumb line in the hand of Zerubbabel.”","sources":{"KJV":{"text":"For who hath despised the day of small things? for they shall rejoice, and shall see the plummet in the hand of Zerubbabel with those seven; they are the eyes of the LORD, which run to and fro through the whole earth."},"BSB":{"text":"For who has despised the day of small things? But these seven eyes of the LORD, which scan the whole earth, will rejoice when they see the plumb line in the hand of Zerubbabel.”"}},"definableWords":["day","LORD","earth","see"],"peopleInVerse":[]},"11":{"text":"Then answered I, and said unto him, What are these two olive trees upon the right side of the candlestick and upon the left side thereof?","ref":"Zechariah 4:11","synthesized":"Then I asked the angel, “What are the two olive trees on the right and left of the lampstand?”","sources":{"KJV":{"text":"Then answered I, and said unto him, What are these two olive trees upon the right side of the candlestick and upon the left side thereof?"},"BSB":{"text":"Then I asked the angel, “What are the two olive trees on the right and left of the lampstand?”"}},"definableWords":["angel","trees"],"peopleInVerse":[]},"12":{"text":"And I answered again, and said unto him, What be these two olive branches which through the two golden pipes empty the golden oil out of themselves?","ref":"Zechariah 4:12","synthesized":"And I questioned him further, “What are the two olive branches beside the two gold pipes from which the golden oil pours?”","sources":{"KJV":{"text":"And I answered again, and said unto him, What be these two olive branches which through the two golden pipes empty the golden oil out of themselves?"},"BSB":{"text":"And I questioned him further, “What are the two olive branches beside the two gold pipes from which the golden oil pours?”"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"And he answered me and said, Knowest thou not what these be? And I said, No, my lord.","ref":"Zechariah 4:13","synthesized":"“Do you not know what these are?” he inquired. “No, my lord,” I replied.","sources":{"KJV":{"text":"And he answered me and said, Knowest thou not what these be? And I said, No, my lord."},"BSB":{"text":"“Do you not know what these are?” he inquired. “No, my lord,” I replied."}},"definableWords":["Lord"],"peopleInVerse":[]},"14":{"text":"Then said he, These are the two anointed ones, that stand by the LORD of the whole earth.","ref":"Zechariah 4:14","synthesized":"So he said, “These are the two anointed ones who are standing beside the Lord of all the earth.”","sources":{"KJV":{"text":"Then said he, These are the two anointed ones, that stand by the LORD of the whole earth."},"BSB":{"text":"So he said, “These are the two anointed ones who are standing beside the Lord of all the earth.”"}},"definableWords":["Lord","earth"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"THE FLYING SCROLL AND THE EPHAH","verses":{"1":{"text":"Then I turned, and lifted up mine eyes, and looked, and behold a flying roll.","ref":"Zechariah 5:1","synthesized":"Again I lifted up my eyes and saw before me a flying scroll.","sources":{"KJV":{"text":"Then I turned, and lifted up mine eyes, and looked, and behold a flying roll."},"BSB":{"text":"Again I lifted up my eyes and saw before me a flying scroll."}},"definableWords":["saw"],"peopleInVerse":[]},"2":{"text":"And he said unto me, What seest thou? And I answered, I see a flying roll; the length thereof is twenty cubits, and the breadth thereof ten cubits.","ref":"Zechariah 5:2","synthesized":"“What do you see?” asked the angel. “I see a flying scroll,” I replied, “twenty cubits long and ten cubits wide.”","sources":{"KJV":{"text":"And he said unto me, What seest thou? And I answered, I see a flying roll; the length thereof is twenty cubits, and the breadth thereof ten cubits."},"BSB":{"text":"“What do you see?” asked the angel. “I see a flying scroll,” I replied, “twenty cubits long and ten cubits wide.”"}},"definableWords":["see","angel"],"peopleInVerse":[]},"3":{"text":"Then said he unto me, This is the curse that goeth forth over the face of the whole earth: for every one that stealeth shall be cut off as on this side according to it; and every one that sweareth shall be cut off as on that side according to it.","ref":"Zechariah 5:3","synthesized":"Then he told me, “This is the curse that is going out over the face of all the land, for according to one side of the scroll, every thief will be removed; and according to the other side, every perjurer will be removed.","sources":{"KJV":{"text":"Then said he unto me, This is the curse that goeth forth over the face of the whole earth: for every one that stealeth shall be cut off as on this side according to it; and every one that sweareth shall be cut off as on that side according to it."},"BSB":{"text":"Then he told me, “This is the curse that is going out over the face of all the land, for according to one side of the scroll, every thief will be removed; and according to the other side, every perjurer will be removed."}},"definableWords":["curse","land","one"],"peopleInVerse":[]},"4":{"text":"I will bring it forth, saith the LORD of hosts, and it shall enter into the house of the thief, and into the house of him that sweareth falsely by my name: and it shall remain in the midst of his house, and shall consume it with the timber thereof and the stones thereof.","ref":"Zechariah 5:4","synthesized":"I will send it out, declares the LORD of Hosts, and it will enter the house of the thief and the house of him who swears falsely by My name. It will remain inside his house and destroy it, down to its timbers and stones.”","sources":{"KJV":{"text":"I will bring it forth, saith the LORD of hosts, and it shall enter into the house of the thief, and into the house of him that sweareth falsely by my name: and it shall remain in the midst of his house, and shall consume it with the timber thereof and the stones thereof."},"BSB":{"text":"I will send it out, declares the LORD of Hosts, and it will enter the house of the thief and the house of him who swears falsely by My name. It will remain inside his house and destroy it, down to its timbers and stones.”"}},"definableWords":["LORD","house","name"],"peopleInVerse":[]},"5":{"text":"Then the angel that talked with me went forth, and said unto me, Lift up now thine eyes, and see what is this that goeth forth.","ref":"Zechariah 5:5","synthesized":"Then the angel who was speaking with me came forward and told me, “Now lift up your eyes and see what is approaching.”","sources":{"KJV":{"text":"Then the angel that talked with me went forth, and said unto me, Lift up now thine eyes, and see what is this that goeth forth."},"BSB":{"text":"Then the angel who was speaking with me came forward and told me, “Now lift up your eyes and see what is approaching.”"}},"definableWords":["angel","see"],"peopleInVerse":[]},"6":{"text":"And I said, What is it? And he said, This is an ephah that goeth forth. He said moreover, This is their resemblance through all the earth.","ref":"Zechariah 5:6","synthesized":"“What is it?” I asked. And he replied, “A measuring basket is going forth.” Then he continued, “This is their iniquity in all the land.”","sources":{"KJV":{"text":"And I said, What is it? And he said, This is an ephah that goeth forth. He said moreover, This is their resemblance through all the earth."},"BSB":{"text":"“What is it?” I asked. And he replied, “A measuring basket is going forth.” Then he continued, “This is their iniquity in all the land.”"}},"definableWords":["iniquity","land"],"peopleInVerse":[]},"7":{"text":"And, behold, there was lifted up a talent of lead: and this is a woman that sitteth in the midst of the ephah.","ref":"Zechariah 5:7","synthesized":"And behold, the cover of lead was raised, and there was a woman sitting inside the basket.","sources":{"KJV":{"text":"And, behold, there was lifted up a talent of lead: and this is a woman that sitteth in the midst of the ephah."},"BSB":{"text":"And behold, the cover of lead was raised, and there was a woman sitting inside the basket."}},"definableWords":["woman"],"peopleInVerse":[]},"8":{"text":"And he said, This is wickedness. And he cast it into the midst of the ephah; and he cast the weight of lead upon the mouth thereof.","ref":"Zechariah 5:8","synthesized":"“This is Wickedness,” he said. And he shoved her down into the basket, pushing down the lead cover over its opening.","sources":{"KJV":{"text":"And he said, This is wickedness. And he cast it into the midst of the ephah; and he cast the weight of lead upon the mouth thereof."},"BSB":{"text":"“This is Wickedness,” he said. And he shoved her down into the basket, pushing down the lead cover over its opening."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Then lifted I up mine eyes, and looked, and, behold, there came out two women, and the wind was in their wings; for they had wings like the wings of a stork: and they lifted up the ephah between the earth and the heaven.","ref":"Zechariah 5:9","synthesized":"Then I lifted up my eyes and saw two women approaching, with the wind in their wings. Their wings were like those of a stork, and they lifted up the basket between heaven and earth.","sources":{"KJV":{"text":"Then lifted I up mine eyes, and looked, and, behold, there came out two women, and the wind was in their wings; for they had wings like the wings of a stork: and they lifted up the ephah between the earth and the heaven."},"BSB":{"text":"Then I lifted up my eyes and saw two women approaching, with the wind in their wings. Their wings were like those of a stork, and they lifted up the basket between heaven and earth."}},"definableWords":["saw","women","heaven","earth"],"peopleInVerse":[]},"10":{"text":"Then said I to the angel that talked with me, Whither do these bear the ephah?","ref":"Zechariah 5:10","synthesized":"“Where are they taking the basket?” I asked the angel who was speaking with me.","sources":{"KJV":{"text":"Then said I to the angel that talked with me, Whither do these bear the ephah?"},"BSB":{"text":"“Where are they taking the basket?” I asked the angel who was speaking with me."}},"definableWords":["angel"],"peopleInVerse":[]},"11":{"text":"And he said unto me, To build it an house in the land of Shinar: and it shall be established, and set there upon her own base.","ref":"Zechariah 5:11","synthesized":"“To build a house for it in the land of Shinar,” he told me. “And when it is ready, the basket will be set there on its pedestal.”","sources":{"KJV":{"text":"And he said unto me, To build it an house in the land of Shinar: and it shall be established, and set there upon her own base."},"BSB":{"text":"“To build a house for it in the land of Shinar,” he told me. “And when it is ready, the basket will be set there on its pedestal.”"}},"definableWords":["house","land"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"THE FOUR CHARIOTS","verses":{"1":{"text":"And I turned, and lifted up mine eyes, and looked, and, behold, there came four chariots out from between two mountains; and the mountains were mountains of brass.","ref":"Zechariah 6:1","synthesized":"And again I lifted up my eyes and saw four chariots coming out from between two mountains—mountains of bronze.","sources":{"KJV":{"text":"And I turned, and lifted up mine eyes, and looked, and, behold, there came four chariots out from between two mountains; and the mountains were mountains of brass."},"BSB":{"text":"And again I lifted up my eyes and saw four chariots coming out from between two mountains—mountains of bronze."}},"definableWords":["saw"],"peopleInVerse":[]},"2":{"text":"In the first chariot were red horses; and in the second chariot black horses;","ref":"Zechariah 6:2","synthesized":"The first chariot had red horses, the second black horses,","sources":{"KJV":{"text":"In the first chariot were red horses; and in the second chariot black horses;"},"BSB":{"text":"The first chariot had red horses, the second black horses,"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"And in the third chariot white horses; and in the fourth chariot grisled and bay horses.","ref":"Zechariah 6:3","synthesized":"the third white horses, and the fourth dappled horses—all of them strong.","sources":{"KJV":{"text":"And in the third chariot white horses; and in the fourth chariot grisled and bay horses."},"BSB":{"text":"the third white horses, and the fourth dappled horses—all of them strong."}},"definableWords":["strong"],"peopleInVerse":[]},"4":{"text":"Then I answered and said unto the angel that talked with me, What are these, my lord?","ref":"Zechariah 6:4","synthesized":"So I inquired of the angel who was speaking with me, “What are these, my lord?”","sources":{"KJV":{"text":"Then I answered and said unto the angel that talked with me, What are these, my lord?"},"BSB":{"text":"So I inquired of the angel who was speaking with me, “What are these, my lord?”"}},"definableWords":["angel","Lord"],"peopleInVerse":[]},"5":{"text":"And the angel answered and said unto me, These are the four spirits of the heavens, which go forth from standing before the LORD of all the earth.","ref":"Zechariah 6:5","synthesized":"And the angel told me, “These are the four spirits of heaven, going forth from their station before the Lord of all the earth.","sources":{"KJV":{"text":"And the angel answered and said unto me, These are the four spirits of the heavens, which go forth from standing before the LORD of all the earth."},"BSB":{"text":"And the angel told me, “These are the four spirits of heaven, going forth from their station before the Lord of all the earth."}},"definableWords":["angel","heaven","Lord","earth"],"peopleInVerse":[]},"6":{"text":"The black horses which are therein go forth into the north country; and the white go forth after them; and the grisled go forth toward the south country.","ref":"Zechariah 6:6","synthesized":"The one with the black horses is going toward the land of the north, the one with the white horses toward the west, and the one with the dappled horses toward the south.”","sources":{"KJV":{"text":"The black horses which are therein go forth into the north country; and the white go forth after them; and the grisled go forth toward the south country."},"BSB":{"text":"The one with the black horses is going toward the land of the north, the one with the white horses toward the west, and the one with the dappled horses toward the south.”"}},"definableWords":["one","land"],"peopleInVerse":[]},"7":{"text":"And the bay went forth, and sought to go that they might walk to and fro through the earth: and he said, Get you hence, walk to and fro through the earth. So they walked to and fro through the earth.","ref":"Zechariah 6:7","synthesized":"As the strong horses went out, they were eager to go and patrol the earth; and the LORD said, “Go and patrol the earth.” So they patrolled the earth.","sources":{"KJV":{"text":"And the bay went forth, and sought to go that they might walk to and fro through the earth: and he said, Get you hence, walk to and fro through the earth. So they walked to and fro through the earth."},"BSB":{"text":"As the strong horses went out, they were eager to go and patrol the earth; and the LORD said, “Go and patrol the earth.” So they patrolled the earth."}},"definableWords":["strong","earth","LORD"],"peopleInVerse":[]},"8":{"text":"Then cried he upon me, and spake unto me, saying, Behold, these that go toward the north country have quieted my spirit in the north country.","ref":"Zechariah 6:8","synthesized":"Then the LORD summoned me and said, “Behold, those going to the land of the north have given rest to My Spirit in the land of the north.”","sources":{"KJV":{"text":"Then cried he upon me, and spake unto me, saying, Behold, these that go toward the north country have quieted my spirit in the north country."},"BSB":{"text":"Then the LORD summoned me and said, “Behold, those going to the land of the north have given rest to My Spirit in the land of the north.”"}},"definableWords":["LORD","land","rest","Spirit"],"peopleInVerse":[]},"9":{"text":"And the word of the LORD came unto me, saying,","ref":"Zechariah 6:9","synthesized":"The word of the LORD also came to me, saying,","sources":{"KJV":{"text":"And the word of the LORD came unto me, saying,"},"BSB":{"text":"The word of the LORD also came to me, saying,"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"10":{"text":"Take of them of the captivity, even of Heldai, of Tobijah, and of Jedaiah, which are come from Babylon, and come thou the same day, and go into the house of Josiah the son of Zephaniah;","ref":"Zechariah 6:10","synthesized":"“Take an offering from the exiles—from Heldai, Tobijah, and Jedaiah, who have arrived from Babylon—and go that same day to the house of Josiah son of Zephaniah.","sources":{"KJV":{"text":"Take of them of the captivity, even of Heldai, of Tobijah, and of Jedaiah, which are come from Babylon, and come thou the same day, and go into the house of Josiah the son of Zephaniah;"},"BSB":{"text":"“Take an offering from the exiles—from Heldai, Tobijah, and Jedaiah, who have arrived from Babylon—and go that same day to the house of Josiah son of Zephaniah."}},"definableWords":["offering","Babylon","day","house","son"],"peopleInVerse":[]},"11":{"text":"Then take silver and gold, and make crowns, and set them upon the head of Joshua the son of Josedech, the high priest;","ref":"Zechariah 6:11","synthesized":"Take silver and gold, make an ornate crown, and set it on the head of the high priest, Joshua son of Jehozadak.","sources":{"KJV":{"text":"Then take silver and gold, and make crowns, and set them upon the head of Joshua the son of Josedech, the high priest;"},"BSB":{"text":"Take silver and gold, make an ornate crown, and set it on the head of the high priest, Joshua son of Jehozadak."}},"definableWords":["make","crown","priest","son"],"peopleInVerse":["Joshua"]},"12":{"text":"And speak unto him, saying, Thus speaketh the LORD of hosts, saying, Behold the man whose name is The BRANCH; and he shall grow up out of his place, and he shall build the temple of the LORD:","ref":"Zechariah 6:12","synthesized":"And you are to tell him that this is what the LORD of Hosts says: ‘Here is a man whose name is the Branch, and He will branch out from His place and build the temple of the LORD.","sources":{"KJV":{"text":"And speak unto him, saying, Thus speaketh the LORD of hosts, saying, Behold the man whose name is The BRANCH; and he shall grow up out of his place, and he shall build the temple of the LORD:"},"BSB":{"text":"And you are to tell him that this is what the LORD of Hosts says: ‘Here is a man whose name is the Branch, and He will branch out from His place and build the temple of the LORD."}},"definableWords":["LORD","man","name","temple","Lord"],"peopleInVerse":[]},"13":{"text":"Even he shall build the temple of the LORD; and he shall bear the glory, and shall sit and rule upon his throne; and he shall be a priest upon his throne: and the counsel of peace shall be between them both.","ref":"Zechariah 6:13","synthesized":"Yes, He will build the temple of the LORD; He will be clothed in splendor and will sit on His throne and rule. And He will be a priest on His throne, and there will be peaceful counsel between the two.’","sources":{"KJV":{"text":"Even he shall build the temple of the LORD; and he shall bear the glory, and shall sit and rule upon his throne; and he shall be a priest upon his throne: and the counsel of peace shall be between them both."},"BSB":{"text":"Yes, He will build the temple of the LORD; He will be clothed in splendor and will sit on His throne and rule. And He will be a priest on His throne, and there will be peaceful counsel between the two.’"}},"definableWords":["temple","LORD","throne","rule","priest"],"peopleInVerse":[]},"14":{"text":"And the crowns shall be to Helem, and to Tobijah, and to Jedaiah, and to Hen the son of Zephaniah, for a memorial in the temple of the LORD.","ref":"Zechariah 6:14","synthesized":"The crown will reside in the temple of the LORD as a memorial to Helem, Tobijah, Jedaiah, and the gracious son of Zephaniah.","sources":{"KJV":{"text":"And the crowns shall be to Helem, and to Tobijah, and to Jedaiah, and to Hen the son of Zephaniah, for a memorial in the temple of the LORD."},"BSB":{"text":"The crown will reside in the temple of the LORD as a memorial to Helem, Tobijah, Jedaiah, and the gracious son of Zephaniah."}},"definableWords":["crown","temple","LORD","son"],"peopleInVerse":[]},"15":{"text":"And they that are far off shall come and build in the temple of the LORD, and ye shall know that the LORD of hosts hath sent me unto you. And this shall come to pass, if ye will diligently obey the voice of the LORD your God.","ref":"Zechariah 6:15","synthesized":"Even those far away will come and build the temple of the LORD, and you will know that the LORD of Hosts has sent Me to you. This will happen if you diligently obey the voice of the LORD your God.”","sources":{"KJV":{"text":"And they that are far off shall come and build in the temple of the LORD, and ye shall know that the LORD of hosts hath sent me unto you. And this shall come to pass, if ye will diligently obey the voice of the LORD your God."},"BSB":{"text":"Even those far away will come and build the temple of the LORD, and you will know that the LORD of Hosts has sent Me to you. This will happen if you diligently obey the voice of the LORD your God.”"}},"definableWords":["temple","LORD","Lord","voice","God"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"FASTS AND TRUE OBEDIENCE","verses":{"1":{"text":"And it came to pass in the fourth year of king Darius, that the word of the LORD came unto Zechariah in the fourth day of the ninth month, even in Chisleu;","ref":"Zechariah 7:1","synthesized":"In the fourth year of King Darius, the word of the LORD came to Zechariah on the fourth day of the ninth month, the month of Chislev.","sources":{"KJV":{"text":"And it came to pass in the fourth year of king Darius, that the word of the LORD came unto Zechariah in the fourth day of the ninth month, even in Chisleu;"},"BSB":{"text":"In the fourth year of King Darius, the word of the LORD came to Zechariah on the fourth day of the ninth month, the month of Chislev."}},"definableWords":["year","King","word","LORD","day"],"peopleInVerse":[]},"2":{"text":"When they had sent unto the house of God Sherezer and Regemmelech, and their men, to pray before the LORD,","ref":"Zechariah 7:2","synthesized":"Now the people of Bethel had sent Sharezer and Regem-melech, along with their men, to plead before the LORD","sources":{"KJV":{"text":"When they had sent unto the house of God Sherezer and Regemmelech, and their men, to pray before the LORD,"},"BSB":{"text":"Now the people of Bethel had sent Sharezer and Regem-melech, along with their men, to plead before the LORD"}},"definableWords":["people","Bethel","men","LORD"],"peopleInVerse":[]},"3":{"text":"And to speak unto the priests which were in the house of the LORD of hosts, and to the prophets, saying, Should I weep in the fifth month, separating myself, as I have done these so many years?","ref":"Zechariah 7:3","synthesized":"by asking the priests of the house of the LORD of Hosts, as well as the prophets, “Should I weep and fast in the fifth month, as I have done these many years?”","sources":{"KJV":{"text":"And to speak unto the priests which were in the house of the LORD of hosts, and to the prophets, saying, Should I weep in the fifth month, separating myself, as I have done these so many years?"},"BSB":{"text":"by asking the priests of the house of the LORD of Hosts, as well as the prophets, “Should I weep and fast in the fifth month, as I have done these many years?”"}},"definableWords":["house","LORD","fast","years"],"peopleInVerse":[]},"4":{"text":"Then came the word of the LORD of hosts unto me, saying,","ref":"Zechariah 7:4","synthesized":"Then the word of the LORD of Hosts came to me, saying,","sources":{"KJV":{"text":"Then came the word of the LORD of hosts unto me, saying,"},"BSB":{"text":"Then the word of the LORD of Hosts came to me, saying,"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"5":{"text":"Speak unto all the people of the land, and to the priests, saying, When ye fasted and mourned in the fifth and seventh month, even those seventy years, did ye at all fast unto me, even to me?","ref":"Zechariah 7:5","synthesized":"“Ask all the people of the land and the priests, ‘When you fasted and mourned in the fifth and seventh months for these seventy years, was it really for Me that you fasted?","sources":{"KJV":{"text":"Speak unto all the people of the land, and to the priests, saying, When ye fasted and mourned in the fifth and seventh month, even those seventy years, did ye at all fast unto me, even to me?"},"BSB":{"text":"“Ask all the people of the land and the priests, ‘When you fasted and mourned in the fifth and seventh months for these seventy years, was it really for Me that you fasted?"}},"definableWords":["people","land","years"],"peopleInVerse":[]},"6":{"text":"And when ye did eat, and when ye did drink, did not ye eat for yourselves, and drink for yourselves?","ref":"Zechariah 7:6","synthesized":"And when you were eating and drinking, were you not doing so simply for yourselves?","sources":{"KJV":{"text":"And when ye did eat, and when ye did drink, did not ye eat for yourselves, and drink for yourselves?"},"BSB":{"text":"And when you were eating and drinking, were you not doing so simply for yourselves?"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Should ye not hear the words which the LORD hath cried by the former prophets, when Jerusalem was inhabited and in prosperity, and the cities thereof round about her, when men inhabited the south and the plain?","ref":"Zechariah 7:7","synthesized":"Are these not the words that the LORD proclaimed through the earlier prophets, when Jerusalem and its surrounding towns were populous and prosperous, and the Negev and the foothills were inhabited?’”","sources":{"KJV":{"text":"Should ye not hear the words which the LORD hath cried by the former prophets, when Jerusalem was inhabited and in prosperity, and the cities thereof round about her, when men inhabited the south and the plain?"},"BSB":{"text":"Are these not the words that the LORD proclaimed through the earlier prophets, when Jerusalem and its surrounding towns were populous and prosperous, and the Negev and the foothills were inhabited?’”"}},"definableWords":["LORD","Jerusalem"],"peopleInVerse":[]},"8":{"text":"And the word of the LORD came unto Zechariah, saying,","ref":"Zechariah 7:8","synthesized":"Then the word of the LORD came to Zechariah, saying,","sources":{"KJV":{"text":"And the word of the LORD came unto Zechariah, saying,"},"BSB":{"text":"Then the word of the LORD came to Zechariah, saying,"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"9":{"text":"Thus speaketh the LORD of hosts, saying, Execute true judgment, and shew mercy and compassions every man to his brother:","ref":"Zechariah 7:9","synthesized":"“This is what the LORD of Hosts says: ‘Administer true justice. Show loving devotion and compassion to one another.","sources":{"KJV":{"text":"Thus speaketh the LORD of hosts, saying, Execute true judgment, and shew mercy and compassions every man to his brother:"},"BSB":{"text":"“This is what the LORD of Hosts says: ‘Administer true justice. Show loving devotion and compassion to one another."}},"definableWords":["LORD","justice","one"],"peopleInVerse":[]},"10":{"text":"And oppress not the widow, nor the fatherless, the stranger, nor the poor; and let none of you imagine evil against his brother in your heart.","ref":"Zechariah 7:10","synthesized":"Do not oppress the widow or the fatherless, the foreigner or the poor. And do not plot evil in your hearts against one another.’","sources":{"KJV":{"text":"And oppress not the widow, nor the fatherless, the stranger, nor the poor; and let none of you imagine evil against his brother in your heart."},"BSB":{"text":"Do not oppress the widow or the fatherless, the foreigner or the poor. And do not plot evil in your hearts against one another.’"}},"definableWords":["widow","or","evil","one"],"peopleInVerse":[]},"11":{"text":"But they refused to hearken, and pulled away the shoulder, and stopped their ears, that they should not hear.","ref":"Zechariah 7:11","synthesized":"But they refused to pay attention and turned a stubborn shoulder; they stopped up their ears from hearing.","sources":{"KJV":{"text":"But they refused to hearken, and pulled away the shoulder, and stopped their ears, that they should not hear."},"BSB":{"text":"But they refused to pay attention and turned a stubborn shoulder; they stopped up their ears from hearing."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Yea, they made their hearts as an adamant stone, lest they should hear the law, and the words which the LORD of hosts hath sent in his spirit by the former prophets: therefore came a great wrath from the LORD of hosts.","ref":"Zechariah 7:12","synthesized":"They made their hearts like flint and would not listen to the law or to the words that the LORD of Hosts had sent by His Spirit through the earlier prophets. Therefore great anger came from the LORD of Hosts.","sources":{"KJV":{"text":"Yea, they made their hearts as an adamant stone, lest they should hear the law, and the words which the LORD of hosts hath sent in his spirit by the former prophets: therefore came a great wrath from the LORD of hosts."},"BSB":{"text":"They made their hearts like flint and would not listen to the law or to the words that the LORD of Hosts had sent by His Spirit through the earlier prophets. Therefore great anger came from the LORD of Hosts."}},"definableWords":["made","law","or","LORD","Spirit","great","anger","Lord"],"peopleInVerse":[]},"13":{"text":"Therefore it is come to pass, that as he cried, and they would not hear; so they cried, and I would not hear, saith the LORD of hosts:","ref":"Zechariah 7:13","synthesized":"And just as I had called and they would not listen, so when they called I would not listen, says the LORD of Hosts.","sources":{"KJV":{"text":"Therefore it is come to pass, that as he cried, and they would not hear; so they cried, and I would not hear, saith the LORD of hosts:"},"BSB":{"text":"And just as I had called and they would not listen, so when they called I would not listen, says the LORD of Hosts."}},"definableWords":["LORD"],"peopleInVerse":[]},"14":{"text":"But I scattered them with a whirlwind among all the nations whom they knew not. Thus the land was desolate after them, that no man passed through nor returned: for they laid the pleasant land desolate.","ref":"Zechariah 7:14","synthesized":"But I scattered them with a whirlwind among all the nations that they had not known, and the land was left desolate behind them so that no one could come or go. Thus they turned the pleasant land into a desolation.”","sources":{"KJV":{"text":"But I scattered them with a whirlwind among all the nations whom they knew not. Thus the land was desolate after them, that no man passed through nor returned: for they laid the pleasant land desolate."},"BSB":{"text":"But I scattered them with a whirlwind among all the nations that they had not known, and the land was left desolate behind them so that no one could come or go. Thus they turned the pleasant land into a desolation.”"}},"definableWords":["nations","land","one","or"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"ZION SHALL BE INHABITED","verses":{"1":{"text":"Again the word of the LORD of hosts came to me, saying,","ref":"Zechariah 8:1","synthesized":"Again the word of the LORD of Hosts came to me, saying:","sources":{"KJV":{"text":"Again the word of the LORD of hosts came to me, saying,"},"BSB":{"text":"Again the word of the LORD of Hosts came to me, saying:"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"2":{"text":"Thus saith the LORD of hosts; I was jealous for Zion with great jealousy, and I was jealous for her with great fury.","ref":"Zechariah 8:2","synthesized":"This is what the LORD of Hosts says: “I am jealous for Zion with great zeal; I am jealous for her with great fervor.”","sources":{"KJV":{"text":"Thus saith the LORD of hosts; I was jealous for Zion with great jealousy, and I was jealous for her with great fury."},"BSB":{"text":"This is what the LORD of Hosts says: “I am jealous for Zion with great zeal; I am jealous for her with great fervor.”"}},"definableWords":["LORD","Zion","great"],"peopleInVerse":[]},"3":{"text":"Thus saith the LORD; I am returned unto Zion, and will dwell in the midst of Jerusalem: and Jerusalem shall be called a city of truth; and the mountain of the LORD of hosts the holy mountain.","ref":"Zechariah 8:3","synthesized":"This is what the LORD says: “I will return to Zion and dwell in Jerusalem. Then Jerusalem will be called the City of Truth, and the mountain of the LORD of Hosts will be called the Holy Mountain.”","sources":{"KJV":{"text":"Thus saith the LORD; I am returned unto Zion, and will dwell in the midst of Jerusalem: and Jerusalem shall be called a city of truth; and the mountain of the LORD of hosts the holy mountain."},"BSB":{"text":"This is what the LORD says: “I will return to Zion and dwell in Jerusalem. Then Jerusalem will be called the City of Truth, and the mountain of the LORD of Hosts will be called the Holy Mountain.”"}},"definableWords":["LORD","Zion","Jerusalem","truth","Lord","holy"],"peopleInVerse":[]},"4":{"text":"Thus saith the LORD of hosts; There shall yet old men and old women dwell in the streets of Jerusalem, and every man with his staff in his hand for very age.","ref":"Zechariah 8:4","synthesized":"This is what the LORD of Hosts says: “Old men and old women will again sit along the streets of Jerusalem, each with a staff in hand because of great age.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; There shall yet old men and old women dwell in the streets of Jerusalem, and every man with his staff in his hand for very age."},"BSB":{"text":"This is what the LORD of Hosts says: “Old men and old women will again sit along the streets of Jerusalem, each with a staff in hand because of great age."}},"definableWords":["LORD","men","women","Jerusalem","great"],"peopleInVerse":[]},"5":{"text":"And the streets of the city shall be full of boys and girls playing in the streets thereof.","ref":"Zechariah 8:5","synthesized":"And the streets of the city will be filled with boys and girls playing there.”","sources":{"KJV":{"text":"And the streets of the city shall be full of boys and girls playing in the streets thereof."},"BSB":{"text":"And the streets of the city will be filled with boys and girls playing there.”"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Thus saith the LORD of hosts; If it be marvellous in the eyes of the remnant of this people in these days, should it also be marvellous in mine eyes? saith the LORD of hosts.","ref":"Zechariah 8:6","synthesized":"This is what the LORD of Hosts says: “If this is impossible in the eyes of the remnant of this people in these days, should it also be impossible in My eyes?” declares the LORD of Hosts.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; If it be marvellous in the eyes of the remnant of this people in these days, should it also be marvellous in mine eyes? saith the LORD of hosts."},"BSB":{"text":"This is what the LORD of Hosts says: “If this is impossible in the eyes of the remnant of this people in these days, should it also be impossible in My eyes?” declares the LORD of Hosts."}},"definableWords":["LORD","remnant","people","days","Lord"],"peopleInVerse":[]},"7":{"text":"Thus saith the LORD of hosts; Behold, I will save my people from the east country, and from the west country;","ref":"Zechariah 8:7","synthesized":"This is what the LORD of Hosts says: “I will save My people from the land of the east and from the land of the west.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; Behold, I will save my people from the east country, and from the west country;"},"BSB":{"text":"This is what the LORD of Hosts says: “I will save My people from the land of the east and from the land of the west."}},"definableWords":["LORD","people","land"],"peopleInVerse":[]},"8":{"text":"And I will bring them, and they shall dwell in the midst of Jerusalem: and they shall be my people, and I will be their God, in truth and in righteousness.","ref":"Zechariah 8:8","synthesized":"I will bring them back to dwell in Jerusalem, where they will be My people, and I will be their faithful and righteous God.”","sources":{"KJV":{"text":"And I will bring them, and they shall dwell in the midst of Jerusalem: and they shall be my people, and I will be their God, in truth and in righteousness."},"BSB":{"text":"I will bring them back to dwell in Jerusalem, where they will be My people, and I will be their faithful and righteous God.”"}},"definableWords":["Jerusalem","people","righteous","God"],"peopleInVerse":[]},"9":{"text":"Thus saith the LORD of hosts; Let your hands be strong, ye that hear in these days these words by the mouth of the prophets, which were in the day that the foundation of the house of the LORD of hosts was laid, that the temple might be built.","ref":"Zechariah 8:9","synthesized":"This is what the LORD of Hosts says: “Let your hands be strong, you who now hear these words spoken by the prophets who were present when the foundations were laid to rebuild the temple, the house of the LORD of Hosts.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; Let your hands be strong, ye that hear in these days these words by the mouth of the prophets, which were in the day that the foundation of the house of the LORD of hosts was laid, that the temple might be built."},"BSB":{"text":"This is what the LORD of Hosts says: “Let your hands be strong, you who now hear these words spoken by the prophets who were present when the foundations were laid to rebuild the temple, the house of the LORD of Hosts."}},"definableWords":["LORD","strong","hear","temple","house","Lord"],"peopleInVerse":[]},"10":{"text":"For before these days there was no hire for man, nor any hire for beast; neither was there any peace to him that went out or came in because of the affliction: for I set all men every one against his neighbour.","ref":"Zechariah 8:10","synthesized":"For before those days neither man nor beast received wages, nor was there safety from the enemy for anyone who came or went, for I had turned every man against his neighbor.","sources":{"KJV":{"text":"For before these days there was no hire for man, nor any hire for beast; neither was there any peace to him that went out or came in because of the affliction: for I set all men every one against his neighbour."},"BSB":{"text":"For before those days neither man nor beast received wages, nor was there safety from the enemy for anyone who came or went, for I had turned every man against his neighbor."}},"definableWords":["days","man","or"],"peopleInVerse":[]},"11":{"text":"But now I will not be unto the residue of this people as in the former days, saith the LORD of hosts.","ref":"Zechariah 8:11","synthesized":"But now I will not treat the remnant of this people as I did in the past,” declares the LORD of Hosts.","sources":{"KJV":{"text":"But now I will not be unto the residue of this people as in the former days, saith the LORD of hosts."},"BSB":{"text":"But now I will not treat the remnant of this people as I did in the past,” declares the LORD of Hosts."}},"definableWords":["remnant","people","LORD"],"peopleInVerse":[]},"12":{"text":"For the seed shall be prosperous; the vine shall give her fruit, and the ground shall give her increase, and the heavens shall give their dew; and I will cause the remnant of this people to possess all these things.","ref":"Zechariah 8:12","synthesized":"“For the seed will be prosperous, the vine will yield its fruit, the ground will yield its produce, and the skies will give their dew. To the remnant of this people I will give all these things as an inheritance.","sources":{"KJV":{"text":"For the seed shall be prosperous; the vine shall give her fruit, and the ground shall give her increase, and the heavens shall give their dew; and I will cause the remnant of this people to possess all these things."},"BSB":{"text":"“For the seed will be prosperous, the vine will yield its fruit, the ground will yield its produce, and the skies will give their dew. To the remnant of this people I will give all these things as an inheritance."}},"definableWords":["seed","ground","remnant","people"],"peopleInVerse":[]},"13":{"text":"And it shall come to pass, that as ye were a curse among the heathen, O house of Judah, and house of Israel; so will I save you, and ye shall be a blessing: fear not, but let your hands be strong.","ref":"Zechariah 8:13","synthesized":"As you have been a curse among the nations, O house of Judah and house of Israel, so I will save you, and you will be a blessing. Do not be afraid; let your hands be strong.”","sources":{"KJV":{"text":"And it shall come to pass, that as ye were a curse among the heathen, O house of Judah, and house of Israel; so will I save you, and ye shall be a blessing: fear not, but let your hands be strong."},"BSB":{"text":"As you have been a curse among the nations, O house of Judah and house of Israel, so I will save you, and you will be a blessing. Do not be afraid; let your hands be strong.”"}},"definableWords":["curse","nations","house","Judah","Israel","blessing","strong"],"peopleInVerse":[]},"14":{"text":"For thus saith the LORD of hosts; As I thought to punish you, when your fathers provoked me to wrath, saith the LORD of hosts, and I repented not:","ref":"Zechariah 8:14","synthesized":"For this is what the LORD of Hosts says: “Just as I resolved to bring disaster upon you when your fathers provoked Me to anger, and I did not relent,” says the LORD of Hosts,","sources":{"KJV":{"text":"For thus saith the LORD of hosts; As I thought to punish you, when your fathers provoked me to wrath, saith the LORD of hosts, and I repented not:"},"BSB":{"text":"For this is what the LORD of Hosts says: “Just as I resolved to bring disaster upon you when your fathers provoked Me to anger, and I did not relent,” says the LORD of Hosts,"}},"definableWords":["LORD","fathers","anger","Lord"],"peopleInVerse":[]},"15":{"text":"So again have I thought in these days to do well unto Jerusalem and to the house of Judah: fear ye not.","ref":"Zechariah 8:15","synthesized":"“so now I have resolved to do good again to Jerusalem and Judah. Do not be afraid.","sources":{"KJV":{"text":"So again have I thought in these days to do well unto Jerusalem and to the house of Judah: fear ye not."},"BSB":{"text":"“so now I have resolved to do good again to Jerusalem and Judah. Do not be afraid."}},"definableWords":["good","Jerusalem","Judah"],"peopleInVerse":[]},"16":{"text":"These are the things that ye shall do; Speak ye every man the truth to his neighbour; execute the judgment of truth and peace in your gates:","ref":"Zechariah 8:16","synthesized":"These are the things you must do: Speak truth to one another, render true and sound judgments in your gates,","sources":{"KJV":{"text":"These are the things that ye shall do; Speak ye every man the truth to his neighbour; execute the judgment of truth and peace in your gates:"},"BSB":{"text":"These are the things you must do: Speak truth to one another, render true and sound judgments in your gates,"}},"definableWords":["truth","one"],"peopleInVerse":[]},"17":{"text":"And let none of you imagine evil in your hearts against his neighbour; and love no false oath: for all these are things that I hate, saith the LORD.","ref":"Zechariah 8:17","synthesized":"do not plot evil in your hearts against your neighbor, and do not love to swear falsely, for I hate all these things,” declares the LORD.","sources":{"KJV":{"text":"And let none of you imagine evil in your hearts against his neighbour; and love no false oath: for all these are things that I hate, saith the LORD."},"BSB":{"text":"do not plot evil in your hearts against your neighbor, and do not love to swear falsely, for I hate all these things,” declares the LORD."}},"definableWords":["evil","love","LORD"],"peopleInVerse":[]},"18":{"text":"And the word of the LORD of hosts came unto me, saying,","ref":"Zechariah 8:18","synthesized":"Then the word of the LORD of Hosts came to me, saying,","sources":{"KJV":{"text":"And the word of the LORD of hosts came unto me, saying,"},"BSB":{"text":"Then the word of the LORD of Hosts came to me, saying,"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"19":{"text":"Thus saith the LORD of hosts; The fast of the fourth month, and the fast of the fifth, and the fast of the seventh, and the fast of the tenth, shall be to the house of Judah joy and gladness, and cheerful feasts; therefore love the truth and peace.","ref":"Zechariah 8:19","synthesized":"“This is what the LORD of Hosts says: The fasts of the fourth, the fifth, the seventh, and the tenth months will become times of joy and gladness, cheerful feasts for the house of Judah. Therefore you are to love both truth and peace.”","sources":{"KJV":{"text":"Thus saith the LORD of hosts; The fast of the fourth month, and the fast of the fifth, and the fast of the seventh, and the fast of the tenth, shall be to the house of Judah joy and gladness, and cheerful feasts; therefore love the truth and peace."},"BSB":{"text":"“This is what the LORD of Hosts says: The fasts of the fourth, the fifth, the seventh, and the tenth months will become times of joy and gladness, cheerful feasts for the house of Judah. Therefore you are to love both truth and peace.”"}},"definableWords":["LORD","joy","house","Judah","love","truth","peace"],"peopleInVerse":[]},"20":{"text":"Thus saith the LORD of hosts; It shall yet come to pass, that there shall come people, and the inhabitants of many cities:","ref":"Zechariah 8:20","synthesized":"This is what the LORD of Hosts says: “Peoples will yet come—the residents of many cities—","sources":{"KJV":{"text":"Thus saith the LORD of hosts; It shall yet come to pass, that there shall come people, and the inhabitants of many cities:"},"BSB":{"text":"This is what the LORD of Hosts says: “Peoples will yet come—the residents of many cities—"}},"definableWords":["LORD"],"peopleInVerse":[]},"21":{"text":"And the inhabitants of one city shall go to another, saying, Let us go speedily to pray before the LORD, and to seek the LORD of hosts: I will go also.","ref":"Zechariah 8:21","synthesized":"and the residents of one city will go to another, saying: ‘Let us go at once to plead before the LORD and to seek the LORD of Hosts. I myself am going.’","sources":{"KJV":{"text":"And the inhabitants of one city shall go to another, saying, Let us go speedily to pray before the LORD, and to seek the LORD of hosts: I will go also."},"BSB":{"text":"and the residents of one city will go to another, saying: ‘Let us go at once to plead before the LORD and to seek the LORD of Hosts. I myself am going.’"}},"definableWords":["one","LORD","seek","Lord"],"peopleInVerse":[]},"22":{"text":"Yea, many people and strong nations shall come to seek the LORD of hosts in Jerusalem, and to pray before the LORD.","ref":"Zechariah 8:22","synthesized":"And many peoples and strong nations will come to seek the LORD of Hosts in Jerusalem and to plead before the LORD.”","sources":{"KJV":{"text":"Yea, many people and strong nations shall come to seek the LORD of hosts in Jerusalem, and to pray before the LORD."},"BSB":{"text":"And many peoples and strong nations will come to seek the LORD of Hosts in Jerusalem and to plead before the LORD.”"}},"definableWords":["strong","nations","seek","LORD","Jerusalem","Lord"],"peopleInVerse":[]},"23":{"text":"Thus saith the LORD of hosts; In those days it shall come to pass, that ten men shall take hold out of all languages of the nations, even shall take hold of the skirt of him that is a Jew, saying, We will go with you: for we have heard that God is with you.","ref":"Zechariah 8:23","synthesized":"This is what the LORD of Hosts says: “In those days ten men from the nations of every tongue will tightly grasp the robe of a Jew, saying, ‘Let us go with you, for we have heard that God is with you.’”","sources":{"KJV":{"text":"Thus saith the LORD of hosts; In those days it shall come to pass, that ten men shall take hold out of all languages of the nations, even shall take hold of the skirt of him that is a Jew, saying, We will go with you: for we have heard that God is with you."},"BSB":{"text":"This is what the LORD of Hosts says: “In those days ten men from the nations of every tongue will tightly grasp the robe of a Jew, saying, ‘Let us go with you, for we have heard that God is with you.’”"}},"definableWords":["LORD","days","men","nations","Jew","God"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"ZION'S KING COMES ON A DONKEY","verses":{"1":{"text":"The burden of the word of the LORD in the land of Hadrach, and Damascus shall be the rest thereof: when the eyes of man, as of all the tribes of Israel, shall be toward the LORD.","ref":"Zechariah 9:1","synthesized":"This is the burden of the word of the LORDagainst the land of Hadrachand Damascus its resting place—for the eyes of menand of all the tribes of Israelare upon the LORD—","sources":{"KJV":{"text":"The burden of the word of the LORD in the land of Hadrach, and Damascus shall be the rest thereof: when the eyes of man, as of all the tribes of Israel, shall be toward the LORD."},"BSB":{"text":"This is the burden of the word of the LORDagainst the land of Hadrachand Damascus its resting place—for the eyes of menand of all the tribes of Israelare upon the LORD—"}},"definableWords":["word","land","LORD"],"peopleInVerse":[]},"2":{"text":"And Hamath also shall border thereby; Tyrus, and Zidon, though it be very wise.","ref":"Zechariah 9:2","synthesized":"and also against Hamath,which borders it,as well as Tyre and Sidon,though they are very shrewd.","sources":{"KJV":{"text":"And Hamath also shall border thereby; Tyrus, and Zidon, though it be very wise."},"BSB":{"text":"and also against Hamath,which borders it,as well as Tyre and Sidon,though they are very shrewd."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"And Tyrus did build herself a strong hold, and heaped up silver as the dust, and fine gold as the mire of the streets.","ref":"Zechariah 9:3","synthesized":"Tyre has built herself a fortress;she has heaped up silver like dust,and gold like the dirt of the streets.","sources":{"KJV":{"text":"And Tyrus did build herself a strong hold, and heaped up silver as the dust, and fine gold as the mire of the streets."},"BSB":{"text":"Tyre has built herself a fortress;she has heaped up silver like dust,and gold like the dirt of the streets."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Behold, the LORD will cast her out, and he will smite her power in the sea; and she shall be devoured with fire.","ref":"Zechariah 9:4","synthesized":"Behold, the Lord will impoverish herand cast her wealth into the sea,and she will be consumed by fire.","sources":{"KJV":{"text":"Behold, the LORD will cast her out, and he will smite her power in the sea; and she shall be devoured with fire."},"BSB":{"text":"Behold, the Lord will impoverish herand cast her wealth into the sea,and she will be consumed by fire."}},"definableWords":["Lord","sea"],"peopleInVerse":[]},"5":{"text":"Ashkelon shall see it, and fear; Gaza also shall see it, and be very sorrowful, and Ekron; for her expectation shall be ashamed; and the king shall perish from Gaza, and Ashkelon shall not be inhabited.","ref":"Zechariah 9:5","synthesized":"Ashkelon will see and fear;Gaza will writhe in agony,as will Ekron,for her hope will wither.There will cease to be a king in Gaza,and Ashkelon will be uninhabited.","sources":{"KJV":{"text":"Ashkelon shall see it, and fear; Gaza also shall see it, and be very sorrowful, and Ekron; for her expectation shall be ashamed; and the king shall perish from Gaza, and Ashkelon shall not be inhabited."},"BSB":{"text":"Ashkelon will see and fear;Gaza will writhe in agony,as will Ekron,for her hope will wither.There will cease to be a king in Gaza,and Ashkelon will be uninhabited."}},"definableWords":["see","fear","hope","king"],"peopleInVerse":[]},"6":{"text":"And a bastard shall dwell in Ashdod, and I will cut off the pride of the Philistines.","ref":"Zechariah 9:6","synthesized":"A mixed race will occupy Ashdod,and I will cut off the pride of the Philistines.","sources":{"KJV":{"text":"And a bastard shall dwell in Ashdod, and I will cut off the pride of the Philistines."},"BSB":{"text":"A mixed race will occupy Ashdod,and I will cut off the pride of the Philistines."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And I will take away his blood out of his mouth, and his abominations from between his teeth: but he that remaineth, even he, shall be for our God, and he shall be as a governor in Judah, and Ekron as a Jebusite.","ref":"Zechariah 9:7","synthesized":"I will remove the blood from their mouthsand the abominations from between their teeth.Then they too will become a remnant for our God;they will become like a clan in Judah,and Ekron will be like the Jebusites.","sources":{"KJV":{"text":"And I will take away his blood out of his mouth, and his abominations from between his teeth: but he that remaineth, even he, shall be for our God, and he shall be as a governor in Judah, and Ekron as a Jebusite."},"BSB":{"text":"I will remove the blood from their mouthsand the abominations from between their teeth.Then they too will become a remnant for our God;they will become like a clan in Judah,and Ekron will be like the Jebusites."}},"definableWords":["blood","remnant","God","Judah"],"peopleInVerse":[]},"8":{"text":"And I will encamp about mine house because of the army, because of him that passeth by, and because of him that returneth: and no oppressor shall pass through them any more: for now have I seen with mine eyes.","ref":"Zechariah 9:8","synthesized":"But I will camp around My house because of an army,because of those who march to and fro,and never again will an oppressor overrun My people,for now I keep watch with My own eyes.","sources":{"KJV":{"text":"And I will encamp about mine house because of the army, because of him that passeth by, and because of him that returneth: and no oppressor shall pass through them any more: for now have I seen with mine eyes."},"BSB":{"text":"But I will camp around My house because of an army,because of those who march to and fro,and never again will an oppressor overrun My people,for now I keep watch with My own eyes."}},"definableWords":["house","people","keep"],"peopleInVerse":[]},"9":{"text":"Rejoice greatly, O daughter of Zion; shout, O daughter of Jerusalem: behold, thy King cometh unto thee: he is just, and having salvation; lowly, and riding upon an ass, and upon a colt the foal of an ass.","ref":"Zechariah 9:9","synthesized":"Rejoice greatly, O Daughter of Zion!Shout in triumph, O Daughter of Jerusalem!See, your King comes to you,righteous and victorious,humble and riding on a donkey,on a colt, the foal of a donkey.","sources":{"KJV":{"text":"Rejoice greatly, O daughter of Zion; shout, O daughter of Jerusalem: behold, thy King cometh unto thee: he is just, and having salvation; lowly, and riding upon an ass, and upon a colt the foal of an ass."},"BSB":{"text":"Rejoice greatly, O Daughter of Zion!Shout in triumph, O Daughter of Jerusalem!See, your King comes to you,righteous and victorious,humble and riding on a donkey,on a colt, the foal of a donkey."}},"definableWords":["daughter","Zion","Jerusalem","see","King","righteous"],"peopleInVerse":[]},"10":{"text":"And I will cut off the chariot from Ephraim, and the horse from Jerusalem, and the battle bow shall be cut off: and he shall speak peace unto the heathen: and his dominion shall be from sea even to sea, and from the river even to the ends of the earth.","ref":"Zechariah 9:10","synthesized":"And I will cut off the chariot from Ephraimand the horse from Jerusalem,and the bow of war will be broken.Then He will proclaim peace to the nations.His dominion will extend from sea to sea,and from the Euphratesto the ends of the earth.","sources":{"KJV":{"text":"And I will cut off the chariot from Ephraim, and the horse from Jerusalem, and the battle bow shall be cut off: and he shall speak peace unto the heathen: and his dominion shall be from sea even to sea, and from the river even to the ends of the earth."},"BSB":{"text":"And I will cut off the chariot from Ephraimand the horse from Jerusalem,and the bow of war will be broken.Then He will proclaim peace to the nations.His dominion will extend from sea to sea,and from the Euphratesto the ends of the earth."}},"definableWords":["Jerusalem","peace","nations","dominion","sea","earth"],"peopleInVerse":[]},"11":{"text":"As for thee also, by the blood of thy covenant I have sent forth thy prisoners out of the pit wherein is no water.","ref":"Zechariah 9:11","synthesized":"As for you,because of the blood of My covenant,I will release your prisonersfrom the waterless pit.","sources":{"KJV":{"text":"As for thee also, by the blood of thy covenant I have sent forth thy prisoners out of the pit wherein is no water."},"BSB":{"text":"As for you,because of the blood of My covenant,I will release your prisonersfrom the waterless pit."}},"definableWords":["blood","covenant"],"peopleInVerse":[]},"12":{"text":"Turn you to the strong hold, ye prisoners of hope: even to day do I declare that I will render double unto thee;","ref":"Zechariah 9:12","synthesized":"Return to your stronghold,O prisoners of hope;even today I declarethat I will restore to you double.","sources":{"KJV":{"text":"Turn you to the strong hold, ye prisoners of hope: even to day do I declare that I will render double unto thee;"},"BSB":{"text":"Return to your stronghold,O prisoners of hope;even today I declarethat I will restore to you double."}},"definableWords":["hope"],"peopleInVerse":[]},"13":{"text":"When I have bent Judah for me, filled the bow with Ephraim, and raised up thy sons, O Zion, against thy sons, O Greece, and made thee as the sword of a mighty man.","ref":"Zechariah 9:13","synthesized":"For I will bend Judah as My bowand fit it with Ephraim.I will rouse your sons, O Zion,against the sons of Greece.I will make you like the swordof a mighty man.","sources":{"KJV":{"text":"When I have bent Judah for me, filled the bow with Ephraim, and raised up thy sons, O Zion, against thy sons, O Greece, and made thee as the sword of a mighty man."},"BSB":{"text":"For I will bend Judah as My bowand fit it with Ephraim.I will rouse your sons, O Zion,against the sons of Greece.I will make you like the swordof a mighty man."}},"definableWords":["Judah","sons","Zion","make","mighty","man"],"peopleInVerse":[]},"14":{"text":"And the LORD shall be seen over them, and his arrow shall go forth as the lightning: and the LORD God shall blow the trumpet, and shall go with whirlwinds of the south.","ref":"Zechariah 9:14","synthesized":"Then the LORD will appear over them,and His arrow will go forth like lightning.The Lord GOD will sound the ram’s hornand advance in the whirlwinds of the south.","sources":{"KJV":{"text":"And the LORD shall be seen over them, and his arrow shall go forth as the lightning: and the LORD God shall blow the trumpet, and shall go with whirlwinds of the south."},"BSB":{"text":"Then the LORD will appear over them,and His arrow will go forth like lightning.The Lord GOD will sound the ram’s hornand advance in the whirlwinds of the south."}},"definableWords":["LORD","Lord","God"],"peopleInVerse":[]},"15":{"text":"The LORD of hosts shall defend them; and they shall devour, and subdue with sling stones; and they shall drink, and make a noise as through wine; and they shall be filled like bowls, and as the corners of the altar.","ref":"Zechariah 9:15","synthesized":"The LORD of Hosts will shield them.They will destroy and conquer with slingstones;they will drink and roar as with wine.And they will be filled like sprinkling bowls,drenched like the corners of the altar.","sources":{"KJV":{"text":"The LORD of hosts shall defend them; and they shall devour, and subdue with sling stones; and they shall drink, and make a noise as through wine; and they shall be filled like bowls, and as the corners of the altar."},"BSB":{"text":"The LORD of Hosts will shield them.They will destroy and conquer with slingstones;they will drink and roar as with wine.And they will be filled like sprinkling bowls,drenched like the corners of the altar."}},"definableWords":["LORD","altar"],"peopleInVerse":[]},"16":{"text":"And the LORD their God shall save them in that day as the flock of his people: for they shall be as the stones of a crown, lifted up as an ensign upon his land.","ref":"Zechariah 9:16","synthesized":"On that day the LORD their God will save themas the flock of His people;for like jewels in a crownthey will sparkle over His land.","sources":{"KJV":{"text":"And the LORD their God shall save them in that day as the flock of his people: for they shall be as the stones of a crown, lifted up as an ensign upon his land."},"BSB":{"text":"On that day the LORD their God will save themas the flock of His people;for like jewels in a crownthey will sparkle over His land."}},"definableWords":["day","LORD","God","people","land"],"peopleInVerse":[]},"17":{"text":"For how great is his goodness, and how great is his beauty! corn shall make the young men cheerful, and new wine the maids.","ref":"Zechariah 9:17","synthesized":"How lovely they will be,and how beautiful!Grain will make the young men flourish,and new wine, the young women.","sources":{"KJV":{"text":"For how great is his goodness, and how great is his beauty! corn shall make the young men cheerful, and new wine the maids."},"BSB":{"text":"How lovely they will be,and how beautiful!Grain will make the young men flourish,and new wine, the young women."}},"definableWords":["make","men","women"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"STRENGTHEN THE HOUSE OF JUDAH","verses":{"1":{"text":"Ask ye of the LORD rain in the time of the latter rain; so the LORD shall make bright clouds, and give them showers of rain, to every one grass in the field.","ref":"Zechariah 10:1","synthesized":"Ask the LORD for rain in springtime;the LORD makes the storm clouds,and He will give everyone showers of rainand crops in the field.","sources":{"KJV":{"text":"Ask ye of the LORD rain in the time of the latter rain; so the LORD shall make bright clouds, and give them showers of rain, to every one grass in the field."},"BSB":{"text":"Ask the LORD for rain in springtime;the LORD makes the storm clouds,and He will give everyone showers of rainand crops in the field."}},"definableWords":["LORD","Lord","field"],"peopleInVerse":[]},"2":{"text":"For the idols have spoken vanity, and the diviners have seen a lie, and have told false dreams; they comfort in vain: therefore they went their way as a flock, they were troubled, because there was no shepherd.","ref":"Zechariah 10:2","synthesized":"For idols speak deceitand diviners see illusions;they tell false dreamsand offer empty comfort.Therefore the people wander like sheep,oppressed for lack of a shepherd.","sources":{"KJV":{"text":"For the idols have spoken vanity, and the diviners have seen a lie, and have told false dreams; they comfort in vain: therefore they went their way as a flock, they were troubled, because there was no shepherd."},"BSB":{"text":"For idols speak deceitand diviners see illusions;they tell false dreamsand offer empty comfort.Therefore the people wander like sheep,oppressed for lack of a shepherd."}},"definableWords":["see","people","shepherd"],"peopleInVerse":[]},"3":{"text":"Mine anger was kindled against the shepherds, and I punished the goats: for the LORD of hosts hath visited his flock the house of Judah, and hath made them as his goodly horse in the battle.","ref":"Zechariah 10:3","synthesized":"“My anger burns against the shepherds,and I will punish the leaders.For the LORD of Hosts attends to His flock,the house of Judah;He will make themlike His royal steed in battle.","sources":{"KJV":{"text":"Mine anger was kindled against the shepherds, and I punished the goats: for the LORD of hosts hath visited his flock the house of Judah, and hath made them as his goodly horse in the battle."},"BSB":{"text":"“My anger burns against the shepherds,and I will punish the leaders.For the LORD of Hosts attends to His flock,the house of Judah;He will make themlike His royal steed in battle."}},"definableWords":["anger","LORD","house","Judah","make"],"peopleInVerse":[]},"4":{"text":"Out of him came forth the corner, out of him the nail, out of him the battle bow, out of him every oppressor together.","ref":"Zechariah 10:4","synthesized":"The cornerstone will come from Judah,the tent peg from him,as well as the battle bowand every ruler together.","sources":{"KJV":{"text":"Out of him came forth the corner, out of him the nail, out of him the battle bow, out of him every oppressor together."},"BSB":{"text":"The cornerstone will come from Judah,the tent peg from him,as well as the battle bowand every ruler together."}},"definableWords":["Judah","ruler"],"peopleInVerse":[]},"5":{"text":"And they shall be as mighty men, which tread down their enemies in the mire of the streets in the battle: and they shall fight, because the LORD is with them, and the riders on horses shall be confounded.","ref":"Zechariah 10:5","synthesized":"They will be like mighty men in battle,trampling the enemy in the mire of the streets.They will fight because the LORD is with them,and they will put the horsemen to shame.","sources":{"KJV":{"text":"And they shall be as mighty men, which tread down their enemies in the mire of the streets in the battle: and they shall fight, because the LORD is with them, and the riders on horses shall be confounded."},"BSB":{"text":"They will be like mighty men in battle,trampling the enemy in the mire of the streets.They will fight because the LORD is with them,and they will put the horsemen to shame."}},"definableWords":["mighty","men","fight","LORD"],"peopleInVerse":[]},"6":{"text":"And I will strengthen the house of Judah, and I will save the house of Joseph, and I will bring them again to place them; for I have mercy upon them: and they shall be as though I had not cast them off: for I am the LORD their God, and will hear them.","ref":"Zechariah 10:6","synthesized":"I will strengthen the house of Judahand save the house of Joseph.I will restore them because I have compassion on them,and they will be as though I had not rejected them.For I am the LORD their God,and I will answer them.","sources":{"KJV":{"text":"And I will strengthen the house of Judah, and I will save the house of Joseph, and I will bring them again to place them; for I have mercy upon them: and they shall be as though I had not cast them off: for I am the LORD their God, and will hear them."},"BSB":{"text":"I will strengthen the house of Judahand save the house of Joseph.I will restore them because I have compassion on them,and they will be as though I had not rejected them.For I am the LORD their God,and I will answer them."}},"definableWords":["house","Joseph","LORD","God"],"peopleInVerse":["Joseph"]},"7":{"text":"And they of Ephraim shall be like a mighty man, and their heart shall rejoice as through wine: yea, their children shall see it, and be glad; their heart shall rejoice in the LORD.","ref":"Zechariah 10:7","synthesized":"Ephraim will be like a mighty man,and their hearts will be glad as with wine.Their children will see it and be joyful;their hearts will rejoice in the LORD.","sources":{"KJV":{"text":"And they of Ephraim shall be like a mighty man, and their heart shall rejoice as through wine: yea, their children shall see it, and be glad; their heart shall rejoice in the LORD."},"BSB":{"text":"Ephraim will be like a mighty man,and their hearts will be glad as with wine.Their children will see it and be joyful;their hearts will rejoice in the LORD."}},"definableWords":["mighty","man","see","LORD"],"peopleInVerse":[]},"8":{"text":"I will hiss for them, and gather them; for I have redeemed them: and they shall increase as they have increased.","ref":"Zechariah 10:8","synthesized":"I will whistle for them to gather,for I have redeemed them;and they will be as numerousas they once were.","sources":{"KJV":{"text":"I will hiss for them, and gather them; for I have redeemed them: and they shall increase as they have increased."},"BSB":{"text":"I will whistle for them to gather,for I have redeemed them;and they will be as numerousas they once were."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And I will sow them among the people: and they shall remember me in far countries; and they shall live with their children, and turn again.","ref":"Zechariah 10:9","synthesized":"Though I sow them among the nations,they will remember Me in distant lands;they and their childrenwill live and return.","sources":{"KJV":{"text":"And I will sow them among the people: and they shall remember me in far countries; and they shall live with their children, and turn again."},"BSB":{"text":"Though I sow them among the nations,they will remember Me in distant lands;they and their childrenwill live and return."}},"definableWords":["nations","remember","live"],"peopleInVerse":[]},"10":{"text":"I will bring them again also out of the land of Egypt, and gather them out of Assyria; and I will bring them into the land of Gilead and Lebanon; and place shall not be found for them.","ref":"Zechariah 10:10","synthesized":"I will bring them back from Egyptand gather them from Assyria.I will bring them to Gilead and Lebanonuntil no more room is found for them.","sources":{"KJV":{"text":"I will bring them again also out of the land of Egypt, and gather them out of Assyria; and I will bring them into the land of Gilead and Lebanon; and place shall not be found for them."},"BSB":{"text":"I will bring them back from Egyptand gather them from Assyria.I will bring them to Gilead and Lebanonuntil no more room is found for them."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And he shall pass through the sea with affliction, and shall smite the waves in the sea, and all the deeps of the river shall dry up: and the pride of Assyria shall be brought down, and the sceptre of Egypt shall depart away.","ref":"Zechariah 10:11","synthesized":"They will pass through the sea of distressand strike the waves of the sea;all the depths of the Nile will dry up.The pride of Assyria will be brought down,and the scepter of Egypt will depart.","sources":{"KJV":{"text":"And he shall pass through the sea with affliction, and shall smite the waves in the sea, and all the deeps of the river shall dry up: and the pride of Assyria shall be brought down, and the sceptre of Egypt shall depart away."},"BSB":{"text":"They will pass through the sea of distressand strike the waves of the sea;all the depths of the Nile will dry up.The pride of Assyria will be brought down,and the scepter of Egypt will depart."}},"definableWords":["sea","scepter","Egypt"],"peopleInVerse":[]},"12":{"text":"And I will strengthen them in the LORD; and they shall walk up and down in his name, saith the LORD.","ref":"Zechariah 10:12","synthesized":"I will strengthen them in the LORD,and in His name they will walk,”declares the LORD.","sources":{"KJV":{"text":"And I will strengthen them in the LORD; and they shall walk up and down in his name, saith the LORD."},"BSB":{"text":"I will strengthen them in the LORD,and in His name they will walk,”declares the LORD."}},"definableWords":["LORD","name","walk","Lord"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"THIRTY PIECES OF SILVER","verses":{"1":{"text":"Open thy doors, O Lebanon, that the fire may devour thy cedars.","ref":"Zechariah 11:1","synthesized":"Open your doors, O Lebanon,that the fire may consume your cedars!","sources":{"KJV":{"text":"Open thy doors, O Lebanon, that the fire may devour thy cedars."},"BSB":{"text":"Open your doors, O Lebanon,that the fire may consume your cedars!"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Howl, fir tree; for the cedar is fallen; because the mighty are spoiled: howl, O ye oaks of Bashan; for the forest of the vintage is come down.","ref":"Zechariah 11:2","synthesized":"Wail, O cypress, for the cedar has fallen;the majestic trees are ruined!Wail, O oaks of Bashan,for the dense forest has been cut down!","sources":{"KJV":{"text":"Howl, fir tree; for the cedar is fallen; because the mighty are spoiled: howl, O ye oaks of Bashan; for the forest of the vintage is come down."},"BSB":{"text":"Wail, O cypress, for the cedar has fallen;the majestic trees are ruined!Wail, O oaks of Bashan,for the dense forest has been cut down!"}},"definableWords":["trees"],"peopleInVerse":[]},"3":{"text":"There is a voice of the howling of the shepherds; for their glory is spoiled: a voice of the roaring of young lions; for the pride of Jordan is spoiled.","ref":"Zechariah 11:3","synthesized":"Listen to the wailing of the shepherds,for their glory is in ruins.Listen to the roaring of the young lions,for the thickets of the Jordan are destroyed.","sources":{"KJV":{"text":"There is a voice of the howling of the shepherds; for their glory is spoiled: a voice of the roaring of young lions; for the pride of Jordan is spoiled."},"BSB":{"text":"Listen to the wailing of the shepherds,for their glory is in ruins.Listen to the roaring of the young lions,for the thickets of the Jordan are destroyed."}},"definableWords":["glory"],"peopleInVerse":[]},"4":{"text":"Thus saith the LORD my God; Feed the flock of the slaughter;","ref":"Zechariah 11:4","synthesized":"This is what the LORD my God says: “Pasture the flock marked for slaughter,","sources":{"KJV":{"text":"Thus saith the LORD my God; Feed the flock of the slaughter;"},"BSB":{"text":"This is what the LORD my God says: “Pasture the flock marked for slaughter,"}},"definableWords":["LORD","God"],"peopleInVerse":[]},"5":{"text":"Whose possessors slay them, and hold themselves not guilty: and they that sell them say, Blessed be the LORD; for I am rich: and their own shepherds pity them not.","ref":"Zechariah 11:5","synthesized":"whose buyers slaughter them without remorse. Those who sell them say, ‘Blessed be the LORD, for I am rich!’ Even their own shepherds have no compassion on them.","sources":{"KJV":{"text":"Whose possessors slay them, and hold themselves not guilty: and they that sell them say, Blessed be the LORD; for I am rich: and their own shepherds pity them not."},"BSB":{"text":"whose buyers slaughter them without remorse. Those who sell them say, ‘Blessed be the LORD, for I am rich!’ Even their own shepherds have no compassion on them."}},"definableWords":["blessed","LORD"],"peopleInVerse":[]},"6":{"text":"For I will no more pity the inhabitants of the land, saith the LORD: but, lo, I will deliver the men every one into his neighbour’s hand, and into the hand of his king: and they shall smite the land, and out of their hand I will not deliver them.","ref":"Zechariah 11:6","synthesized":"For I will no longer have compassion on the people of the land, declares the LORD, but behold, I will cause each man to fall into the hands of his neighbor and his king, who will devastate the land, and I will not deliver it from their hands.”","sources":{"KJV":{"text":"For I will no more pity the inhabitants of the land, saith the LORD: but, lo, I will deliver the men every one into his neighbour’s hand, and into the hand of his king: and they shall smite the land, and out of their hand I will not deliver them."},"BSB":{"text":"For I will no longer have compassion on the people of the land, declares the LORD, but behold, I will cause each man to fall into the hands of his neighbor and his king, who will devastate the land, and I will not deliver it from their hands.”"}},"definableWords":["people","land","LORD","man","king","deliver"],"peopleInVerse":[]},"7":{"text":"And I will feed the flock of slaughter, even you, O poor of the flock. And I took unto me two staves; the one I called Beauty, and the other I called Bands; and I fed the flock.","ref":"Zechariah 11:7","synthesized":"So I pastured the flock marked for slaughter, especially the afflicted of the flock. Then I took for myself two staffs, calling one Favor and the other Union, and I pastured the flock.","sources":{"KJV":{"text":"And I will feed the flock of slaughter, even you, O poor of the flock. And I took unto me two staves; the one I called Beauty, and the other I called Bands; and I fed the flock."},"BSB":{"text":"So I pastured the flock marked for slaughter, especially the afflicted of the flock. Then I took for myself two staffs, calling one Favor and the other Union, and I pastured the flock."}},"definableWords":["one"],"peopleInVerse":[]},"8":{"text":"Three shepherds also I cut off in one month; and my soul lothed them, and their soul also abhorred me.","ref":"Zechariah 11:8","synthesized":"And in one month I dismissed three shepherds. My soul grew impatient with the flock, and their souls also detested me.","sources":{"KJV":{"text":"Three shepherds also I cut off in one month; and my soul lothed them, and their soul also abhorred me."},"BSB":{"text":"And in one month I dismissed three shepherds. My soul grew impatient with the flock, and their souls also detested me."}},"definableWords":["one","soul"],"peopleInVerse":[]},"9":{"text":"Then said I, I will not feed you: that that dieth, let it die; and that that is to be cut off, let it be cut off; and let the rest eat every one the flesh of another.","ref":"Zechariah 11:9","synthesized":"Then I said, “I will no longer shepherd you. Let the dying die, and the perishing perish; and let those who remain devour one another’s flesh.”","sources":{"KJV":{"text":"Then said I, I will not feed you: that that dieth, let it die; and that that is to be cut off, let it be cut off; and let the rest eat every one the flesh of another."},"BSB":{"text":"Then I said, “I will no longer shepherd you. Let the dying die, and the perishing perish; and let those who remain devour one another’s flesh.”"}},"definableWords":["shepherd","die","one","flesh"],"peopleInVerse":[]},"10":{"text":"And I took my staff, even Beauty, and cut it asunder, that I might break my covenant which I had made with all the people.","ref":"Zechariah 11:10","synthesized":"Next I took my staff called Favor and cut it in two, revoking the covenant I had made with all the nations.","sources":{"KJV":{"text":"And I took my staff, even Beauty, and cut it asunder, that I might break my covenant which I had made with all the people."},"BSB":{"text":"Next I took my staff called Favor and cut it in two, revoking the covenant I had made with all the nations."}},"definableWords":["covenant","made","nations"],"peopleInVerse":[]},"11":{"text":"And it was broken in that day: and so the poor of the flock that waited upon me knew that it was the word of the LORD.","ref":"Zechariah 11:11","synthesized":"It was revoked on that day, and so the afflicted of the flock who were watching me knew that it was the word of the LORD.","sources":{"KJV":{"text":"And it was broken in that day: and so the poor of the flock that waited upon me knew that it was the word of the LORD."},"BSB":{"text":"It was revoked on that day, and so the afflicted of the flock who were watching me knew that it was the word of the LORD."}},"definableWords":["day","word","LORD"],"peopleInVerse":[]},"12":{"text":"And I said unto them, If ye think good, give me my price; and if not, forbear. So they weighed for my price thirty pieces of silver.","ref":"Zechariah 11:12","synthesized":"Then I told them, “If it seems right to you, give me my wages; but if not, keep them.” So they weighed out my wages, thirty pieces of silver.","sources":{"KJV":{"text":"And I said unto them, If ye think good, give me my price; and if not, forbear. So they weighed for my price thirty pieces of silver."},"BSB":{"text":"Then I told them, “If it seems right to you, give me my wages; but if not, keep them.” So they weighed out my wages, thirty pieces of silver."}},"definableWords":["keep"],"peopleInVerse":[]},"13":{"text":"And the LORD said unto me, Cast it unto the potter: a goodly price that I was prised at of them. And I took the thirty pieces of silver, and cast them to the potter in the house of the LORD.","ref":"Zechariah 11:13","synthesized":"And the LORD said to me, “Throw it to the potter”—this magnificent price at which they valued me. So I took the thirty pieces of silver and threw them to the potter in the house of the LORD.","sources":{"KJV":{"text":"And the LORD said unto me, Cast it unto the potter: a goodly price that I was prised at of them. And I took the thirty pieces of silver, and cast them to the potter in the house of the LORD."},"BSB":{"text":"And the LORD said to me, “Throw it to the potter”—this magnificent price at which they valued me. So I took the thirty pieces of silver and threw them to the potter in the house of the LORD."}},"definableWords":["LORD","house","Lord"],"peopleInVerse":[]},"14":{"text":"Then I cut asunder mine other staff, even Bands, that I might break the brotherhood between Judah and Israel.","ref":"Zechariah 11:14","synthesized":"Then I cut in two my second staff called Union, breaking the brotherhood between Judah and Israel.","sources":{"KJV":{"text":"Then I cut asunder mine other staff, even Bands, that I might break the brotherhood between Judah and Israel."},"BSB":{"text":"Then I cut in two my second staff called Union, breaking the brotherhood between Judah and Israel."}},"definableWords":["Judah","Israel"],"peopleInVerse":[]},"15":{"text":"And the LORD said unto me, Take unto thee yet the instruments of a foolish shepherd.","ref":"Zechariah 11:15","synthesized":"And the LORD said to me: “Take up once more the equipment of a foolish shepherd.","sources":{"KJV":{"text":"And the LORD said unto me, Take unto thee yet the instruments of a foolish shepherd."},"BSB":{"text":"And the LORD said to me: “Take up once more the equipment of a foolish shepherd."}},"definableWords":["LORD","shepherd"],"peopleInVerse":[]},"16":{"text":"For, lo, I will raise up a shepherd in the land, which shall not visit those that be cut off, neither shall seek the young one, nor heal that that is broken, nor feed that that standeth still: but he shall eat the flesh of the fat, and tear their claws in pieces.","ref":"Zechariah 11:16","synthesized":"For behold, I will raise up a shepherd in the land who will neither care for the lost, nor seek the young, nor heal the broken, nor sustain the healthy, but he will devour the flesh of the choice sheep and tear off their hooves.","sources":{"KJV":{"text":"For, lo, I will raise up a shepherd in the land, which shall not visit those that be cut off, neither shall seek the young one, nor heal that that is broken, nor feed that that standeth still: but he shall eat the flesh of the fat, and tear their claws in pieces."},"BSB":{"text":"For behold, I will raise up a shepherd in the land who will neither care for the lost, nor seek the young, nor heal the broken, nor sustain the healthy, but he will devour the flesh of the choice sheep and tear off their hooves."}},"definableWords":["shepherd","land","seek","heal","flesh"],"peopleInVerse":[]},"17":{"text":"Woe to the idol shepherd that leaveth the flock! the sword shall be upon his arm, and upon his right eye: his arm shall be clean dried up, and his right eye shall be utterly darkened.","ref":"Zechariah 11:17","synthesized":"Woe to the worthless shepherd,who deserts the flock!May a sword strike his armand his right eye!May his arm be completely witheredand his right eye utterly blinded!”","sources":{"KJV":{"text":"Woe to the idol shepherd that leaveth the flock! the sword shall be upon his arm, and upon his right eye: his arm shall be clean dried up, and his right eye shall be utterly darkened."},"BSB":{"text":"Woe to the worthless shepherd,who deserts the flock!May a sword strike his armand his right eye!May his arm be completely witheredand his right eye utterly blinded!”"}},"definableWords":["shepherd"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"THEY SHALL LOOK ON HIM WHOM THEY PIERCED","verses":{"1":{"text":"The burden of the word of the LORD for Israel, saith the LORD, which stretcheth forth the heavens, and layeth the foundation of the earth, and formeth the spirit of man within him.","ref":"Zechariah 12:1","synthesized":"This is the burden of the word of the LORD concerning Israel.  Thus declares the LORD, who stretches out the heavens and lays the foundation of the earth, who forms the spirit of man within him:","sources":{"KJV":{"text":"The burden of the word of the LORD for Israel, saith the LORD, which stretcheth forth the heavens, and layeth the foundation of the earth, and formeth the spirit of man within him."},"BSB":{"text":"This is the burden of the word of the LORD concerning Israel.  Thus declares the LORD, who stretches out the heavens and lays the foundation of the earth, who forms the spirit of man within him:"}},"definableWords":["word","LORD","Israel","Lord","heavens","earth","spirit","man"],"peopleInVerse":[]},"2":{"text":"Behold, I will make Jerusalem a cup of trembling unto all the people round about, when they shall be in the siege both against Judah and against Jerusalem.","ref":"Zechariah 12:2","synthesized":"“Behold, I will make Jerusalem a cup of drunkenness to all the surrounding peoples. Judah will be besieged, as well as Jerusalem.","sources":{"KJV":{"text":"Behold, I will make Jerusalem a cup of trembling unto all the people round about, when they shall be in the siege both against Judah and against Jerusalem."},"BSB":{"text":"“Behold, I will make Jerusalem a cup of drunkenness to all the surrounding peoples. Judah will be besieged, as well as Jerusalem."}},"definableWords":["make","Jerusalem","Judah"],"peopleInVerse":[]},"3":{"text":"And in that day will I make Jerusalem a burdensome stone for all people: all that burden themselves with it shall be cut in pieces, though all the people of the earth be gathered together against it.","ref":"Zechariah 12:3","synthesized":"On that day, when all the nations of the earth gather against her, I will make Jerusalem a heavy stone for all the peoples; all who would heave it away will be severely injured.","sources":{"KJV":{"text":"And in that day will I make Jerusalem a burdensome stone for all people: all that burden themselves with it shall be cut in pieces, though all the people of the earth be gathered together against it."},"BSB":{"text":"On that day, when all the nations of the earth gather against her, I will make Jerusalem a heavy stone for all the peoples; all who would heave it away will be severely injured."}},"definableWords":["day","nations","earth","make","Jerusalem","stone"],"peopleInVerse":[]},"4":{"text":"In that day, saith the LORD, I will smite every horse with astonishment, and his rider with madness: and I will open mine eyes upon the house of Judah, and will smite every horse of the people with blindness.","ref":"Zechariah 12:4","synthesized":"On that day, declares the LORD, I will strike every horse with panic, and every rider with madness. I will keep a watchful eye on the house of Judah, but I will strike with blindness all the horses of the nations.","sources":{"KJV":{"text":"In that day, saith the LORD, I will smite every horse with astonishment, and his rider with madness: and I will open mine eyes upon the house of Judah, and will smite every horse of the people with blindness."},"BSB":{"text":"On that day, declares the LORD, I will strike every horse with panic, and every rider with madness. I will keep a watchful eye on the house of Judah, but I will strike with blindness all the horses of the nations."}},"definableWords":["day","LORD","keep","house","Judah","nations"],"peopleInVerse":[]},"5":{"text":"And the governors of Judah shall say in their heart, The inhabitants of Jerusalem shall be my strength in the LORD of hosts their God.","ref":"Zechariah 12:5","synthesized":"Then the leaders of Judah will say in their hearts: ‘The people of Jerusalem are my strength, for the LORD of Hosts is their God.’","sources":{"KJV":{"text":"And the governors of Judah shall say in their heart, The inhabitants of Jerusalem shall be my strength in the LORD of hosts their God."},"BSB":{"text":"Then the leaders of Judah will say in their hearts: ‘The people of Jerusalem are my strength, for the LORD of Hosts is their God.’"}},"definableWords":["Judah","people","Jerusalem","LORD","God"],"peopleInVerse":[]},"6":{"text":"In that day will I make the governors of Judah like an hearth of fire among the wood, and like a torch of fire in a sheaf; and they shall devour all the people round about, on the right hand and on the left: and Jerusalem shall be inhabited again in her own place, even in Jerusalem.","ref":"Zechariah 12:6","synthesized":"On that day I will make the clans of Judah like a firepot in a woodpile, like a flaming torch among the sheaves; they will consume all the peoples around them on the right and on the left, while the people of Jerusalem remain secure there.","sources":{"KJV":{"text":"In that day will I make the governors of Judah like an hearth of fire among the wood, and like a torch of fire in a sheaf; and they shall devour all the people round about, on the right hand and on the left: and Jerusalem shall be inhabited again in her own place, even in Jerusalem."},"BSB":{"text":"On that day I will make the clans of Judah like a firepot in a woodpile, like a flaming torch among the sheaves; they will consume all the peoples around them on the right and on the left, while the people of Jerusalem remain secure there."}},"definableWords":["day","make","Judah","people","Jerusalem"],"peopleInVerse":[]},"7":{"text":"The LORD also shall save the tents of Judah first, that the glory of the house of David and the glory of the inhabitants of Jerusalem do not magnify themselves against Judah.","ref":"Zechariah 12:7","synthesized":"The LORD will save the tents of Judah first, so that the glory of the house of David and of the people of Jerusalem may not be greater than that of Judah.","sources":{"KJV":{"text":"The LORD also shall save the tents of Judah first, that the glory of the house of David and the glory of the inhabitants of Jerusalem do not magnify themselves against Judah."},"BSB":{"text":"The LORD will save the tents of Judah first, so that the glory of the house of David and of the people of Jerusalem may not be greater than that of Judah."}},"definableWords":["LORD","Judah","glory","house","people","Jerusalem"],"peopleInVerse":["David"]},"8":{"text":"In that day shall the LORD defend the inhabitants of Jerusalem; and he that is feeble among them at that day shall be as David; and the house of David shall be as God, as the angel of the LORD before them.","ref":"Zechariah 12:8","synthesized":"On that day the LORD will defend the people of Jerusalem, so that the weakest among them will be like David, and the house of David will be like God, like the angel of the LORD going before them.","sources":{"KJV":{"text":"In that day shall the LORD defend the inhabitants of Jerusalem; and he that is feeble among them at that day shall be as David; and the house of David shall be as God, as the angel of the LORD before them."},"BSB":{"text":"On that day the LORD will defend the people of Jerusalem, so that the weakest among them will be like David, and the house of David will be like God, like the angel of the LORD going before them."}},"definableWords":["day","LORD","people","Jerusalem","house","God","angel","Lord"],"peopleInVerse":["David"]},"9":{"text":"And it shall come to pass in that day, that I will seek to destroy all the nations that come against Jerusalem.","ref":"Zechariah 12:9","synthesized":"So on that day I will set out to destroy all the nations that come against Jerusalem.","sources":{"KJV":{"text":"And it shall come to pass in that day, that I will seek to destroy all the nations that come against Jerusalem."},"BSB":{"text":"So on that day I will set out to destroy all the nations that come against Jerusalem."}},"definableWords":["day","nations","Jerusalem"],"peopleInVerse":[]},"10":{"text":"And I will pour upon the house of David, and upon the inhabitants of Jerusalem, the spirit of grace and of supplications: and they shall look upon me whom they have pierced, and they shall mourn for him, as one mourneth for his only son, and shall be in bitterness for him, as one that is in bitterness for his firstborn.","ref":"Zechariah 12:10","synthesized":"Then I will pour out on the house of David and on the people of Jerusalem a spirit of grace and prayer, and they will look on Me, the One they have pierced. They will mourn for Him as one mourns for an only child, and grieve bitterly for Him as one grieves for a firstborn son.","sources":{"KJV":{"text":"And I will pour upon the house of David, and upon the inhabitants of Jerusalem, the spirit of grace and of supplications: and they shall look upon me whom they have pierced, and they shall mourn for him, as one mourneth for his only son, and shall be in bitterness for him, as one that is in bitterness for his firstborn."},"BSB":{"text":"Then I will pour out on the house of David and on the people of Jerusalem a spirit of grace and prayer, and they will look on Me, the One they have pierced. They will mourn for Him as one mourns for an only child, and grieve bitterly for Him as one grieves for a firstborn son."}},"definableWords":["house","people","Jerusalem","spirit","grace","prayer","one","son"],"peopleInVerse":["David"]},"11":{"text":"In that day shall there be a great mourning in Jerusalem, as the mourning of Hadadrimmon in the valley of Megiddon.","ref":"Zechariah 12:11","synthesized":"On that day the wailing in Jerusalem will be as great as the wailing of Hadad-rimmon in the plain of Megiddo.","sources":{"KJV":{"text":"In that day shall there be a great mourning in Jerusalem, as the mourning of Hadadrimmon in the valley of Megiddon."},"BSB":{"text":"On that day the wailing in Jerusalem will be as great as the wailing of Hadad-rimmon in the plain of Megiddo."}},"definableWords":["day","Jerusalem","great"],"peopleInVerse":[]},"12":{"text":"And the land shall mourn, every family apart; the family of the house of David apart, and their wives apart; the family of the house of Nathan apart, and their wives apart;","ref":"Zechariah 12:12","synthesized":"The land will mourn, each clan on its own: the clan of the house of David and their wives, the clan of the house of Nathan and their wives,","sources":{"KJV":{"text":"And the land shall mourn, every family apart; the family of the house of David apart, and their wives apart; the family of the house of Nathan apart, and their wives apart;"},"BSB":{"text":"The land will mourn, each clan on its own: the clan of the house of David and their wives, the clan of the house of Nathan and their wives,"}},"definableWords":["land","house"],"peopleInVerse":["David"]},"13":{"text":"The family of the house of Levi apart, and their wives apart; the family of Shimei apart, and their wives apart;","ref":"Zechariah 12:13","synthesized":"the clan of the house of Levi and their wives, the clan of Shimei and their wives,","sources":{"KJV":{"text":"The family of the house of Levi apart, and their wives apart; the family of Shimei apart, and their wives apart;"},"BSB":{"text":"the clan of the house of Levi and their wives, the clan of Shimei and their wives,"}},"definableWords":["house","Levi"],"peopleInVerse":[]},"14":{"text":"All the families that remain, every family apart, and their wives apart.","ref":"Zechariah 12:14","synthesized":"and all the remaining clans and their wives.","sources":{"KJV":{"text":"All the families that remain, every family apart, and their wives apart."},"BSB":{"text":"and all the remaining clans and their wives."}},"definableWords":[],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"FOUNTAIN OPENED FOR SIN AND UNCLEANNESS","verses":{"1":{"text":"In that day there shall be a fountain opened to the house of David and to the inhabitants of Jerusalem for sin and for uncleanness.","ref":"Zechariah 13:1","synthesized":"“On that day a fountain will be opened to the house of David and the people of Jerusalem, to cleanse them from sin and impurity.","sources":{"KJV":{"text":"In that day there shall be a fountain opened to the house of David and to the inhabitants of Jerusalem for sin and for uncleanness."},"BSB":{"text":"“On that day a fountain will be opened to the house of David and the people of Jerusalem, to cleanse them from sin and impurity."}},"definableWords":["day","house","people","Jerusalem","cleanse","sin"],"peopleInVerse":["David"]},"2":{"text":"And it shall come to pass in that day, saith the LORD of hosts, that I will cut off the names of the idols out of the land, and they shall no more be remembered: and also I will cause the prophets and the unclean spirit to pass out of the land.","ref":"Zechariah 13:2","synthesized":"And on that day, declares the LORD of Hosts, I will erase the names of the idols from the land, and they will no longer be remembered. I will also remove the prophets and the spirit of impurity from the land.","sources":{"KJV":{"text":"And it shall come to pass in that day, saith the LORD of hosts, that I will cut off the names of the idols out of the land, and they shall no more be remembered: and also I will cause the prophets and the unclean spirit to pass out of the land."},"BSB":{"text":"And on that day, declares the LORD of Hosts, I will erase the names of the idols from the land, and they will no longer be remembered. I will also remove the prophets and the spirit of impurity from the land."}},"definableWords":["day","LORD","land","remembered","spirit"],"peopleInVerse":[]},"3":{"text":"And it shall come to pass, that when any shall yet prophesy, then his father and his mother that begat him shall say unto him, Thou shalt not live; for thou speakest lies in the name of the LORD: and his father and his mother that begat him shall thrust him through when he prophesieth.","ref":"Zechariah 13:3","synthesized":"And if anyone still prophesies, his father and mother who bore him will say to him, ‘You shall not remain alive, because you have spoken falsely in the name of the LORD.’ When he prophesies, his father and mother who bore him will pierce him through.","sources":{"KJV":{"text":"And it shall come to pass, that when any shall yet prophesy, then his father and his mother that begat him shall say unto him, Thou shalt not live; for thou speakest lies in the name of the LORD: and his father and his mother that begat him shall thrust him through when he prophesieth."},"BSB":{"text":"And if anyone still prophesies, his father and mother who bore him will say to him, ‘You shall not remain alive, because you have spoken falsely in the name of the LORD.’ When he prophesies, his father and mother who bore him will pierce him through."}},"definableWords":["father","mother","name","LORD","Father"],"peopleInVerse":[]},"4":{"text":"And it shall come to pass in that day, that the prophets shall be ashamed every one of his vision, when he hath prophesied; neither shall they wear a rough garment to deceive:","ref":"Zechariah 13:4","synthesized":"And on that day every prophet who prophesies will be ashamed of his vision, and he will not put on a hairy cloak in order to deceive.","sources":{"KJV":{"text":"And it shall come to pass in that day, that the prophets shall be ashamed every one of his vision, when he hath prophesied; neither shall they wear a rough garment to deceive:"},"BSB":{"text":"And on that day every prophet who prophesies will be ashamed of his vision, and he will not put on a hairy cloak in order to deceive."}},"definableWords":["day","prophet"],"peopleInVerse":[]},"5":{"text":"But he shall say, I am no prophet, I am an husbandman; for man taught me to keep cattle from my youth.","ref":"Zechariah 13:5","synthesized":"He will say, ‘I am not a prophet; I work the land, for I was purchased as a servant in my youth.’","sources":{"KJV":{"text":"But he shall say, I am no prophet, I am an husbandman; for man taught me to keep cattle from my youth."},"BSB":{"text":"He will say, ‘I am not a prophet; I work the land, for I was purchased as a servant in my youth.’"}},"definableWords":["prophet","work","land","servant"],"peopleInVerse":[]},"6":{"text":"And one shall say unto him, What are these wounds in thine hands? Then he shall answer, Those with which I was wounded in the house of my friends.","ref":"Zechariah 13:6","synthesized":"If someone asks him, ‘What are these wounds on your chest?’ he will answer, ‘These are the wounds I received in the house of my friends.’","sources":{"KJV":{"text":"And one shall say unto him, What are these wounds in thine hands? Then he shall answer, Those with which I was wounded in the house of my friends."},"BSB":{"text":"If someone asks him, ‘What are these wounds on your chest?’ he will answer, ‘These are the wounds I received in the house of my friends.’"}},"definableWords":["house"],"peopleInVerse":[]},"7":{"text":"Awake, O sword, against my shepherd, and against the man that is my fellow, saith the LORD of hosts: smite the shepherd, and the sheep shall be scattered: and I will turn mine hand upon the little ones.","ref":"Zechariah 13:7","synthesized":"Awake, O sword, against My Shepherd,against the man who is My Companion,declares the LORD of Hosts.Strike the Shepherd, and the sheep will be scattered,and I will turn My hand against the little ones.","sources":{"KJV":{"text":"Awake, O sword, against my shepherd, and against the man that is my fellow, saith the LORD of hosts: smite the shepherd, and the sheep shall be scattered: and I will turn mine hand upon the little ones."},"BSB":{"text":"Awake, O sword, against My Shepherd,against the man who is My Companion,declares the LORD of Hosts.Strike the Shepherd, and the sheep will be scattered,and I will turn My hand against the little ones."}},"definableWords":["shepherd","man","LORD"],"peopleInVerse":[]},"8":{"text":"And it shall come to pass, that in all the land, saith the LORD, two parts therein shall be cut off and die; but the third shall be left therein.","ref":"Zechariah 13:8","synthesized":"And in all the land,declares the LORD,two-thirds will be cut off and perish,but a third will be left in it.","sources":{"KJV":{"text":"And it shall come to pass, that in all the land, saith the LORD, two parts therein shall be cut off and die; but the third shall be left therein."},"BSB":{"text":"And in all the land,declares the LORD,two-thirds will be cut off and perish,but a third will be left in it."}},"definableWords":["land","LORD"],"peopleInVerse":[]},"9":{"text":"And I will bring the third part through the fire, and will refine them as silver is refined, and will try them as gold is tried: they shall call on my name, and I will hear them: I will say, It is my people: and they shall say, The LORD is my God.","ref":"Zechariah 13:9","synthesized":"This third I will bring through the fire;I will refine them like silverand test them like gold.They will call on My name,and I will answer them.I will say, ‘They are My people,’and they will say, ‘The LORD is our God.’”","sources":{"KJV":{"text":"And I will bring the third part through the fire, and will refine them as silver is refined, and will try them as gold is tried: they shall call on my name, and I will hear them: I will say, It is my people: and they shall say, The LORD is my God."},"BSB":{"text":"This third I will bring through the fire;I will refine them like silverand test them like gold.They will call on My name,and I will answer them.I will say, ‘They are My people,’and they will say, ‘The LORD is our God.’”"}},"definableWords":["name","people","LORD","God"],"peopleInVerse":[]}}},"14":{"chapter":"14","title":"THE DAY OF THE LORD","verses":{"1":{"text":"Behold, the day of the LORD cometh, and thy spoil shall be divided in the midst of thee.","ref":"Zechariah 14:1","synthesized":"Behold, a day of the LORD is coming when your plunder will be divided in your presence.","sources":{"KJV":{"text":"Behold, the day of the LORD cometh, and thy spoil shall be divided in the midst of thee."},"BSB":{"text":"Behold, a day of the LORD is coming when your plunder will be divided in your presence."}},"definableWords":["day","LORD"],"peopleInVerse":[]},"2":{"text":"For I will gather all nations against Jerusalem to battle; and the city shall be taken, and the houses rifled, and the women ravished; and half of the city shall go forth into captivity, and the residue of the people shall not be cut off from the city.","ref":"Zechariah 14:2","synthesized":"For I will gather all the nations for battle against Jerusalem, and the city will be captured, the houses looted, and the women ravished. Half of the city will go into exile, but the rest of the people will not be removed from the city.","sources":{"KJV":{"text":"For I will gather all nations against Jerusalem to battle; and the city shall be taken, and the houses rifled, and the women ravished; and half of the city shall go forth into captivity, and the residue of the people shall not be cut off from the city."},"BSB":{"text":"For I will gather all the nations for battle against Jerusalem, and the city will be captured, the houses looted, and the women ravished. Half of the city will go into exile, but the rest of the people will not be removed from the city."}},"definableWords":["nations","Jerusalem","women","rest","people"],"peopleInVerse":[]},"3":{"text":"Then shall the LORD go forth, and fight against those nations, as when he fought in the day of battle.","ref":"Zechariah 14:3","synthesized":"Then the LORD will go out to fight against those nations, as He fights in the day of battle.","sources":{"KJV":{"text":"Then shall the LORD go forth, and fight against those nations, as when he fought in the day of battle."},"BSB":{"text":"Then the LORD will go out to fight against those nations, as He fights in the day of battle."}},"definableWords":["LORD","fight","nations","day"],"peopleInVerse":[]},"4":{"text":"And his feet shall stand in that day upon the mount of Olives, which is before Jerusalem on the east, and the mount of Olives shall cleave in the midst thereof toward the east and toward the west, and there shall be a very great valley; and half of the mountain shall remove toward the north, and half of it toward the south.","ref":"Zechariah 14:4","synthesized":"On that day His feet will stand on the Mount of Olives, east of Jerusalem, and the Mount of Olives will be split in two from east to west, forming a great valley, with half the mountain moving to the north and half to the south.","sources":{"KJV":{"text":"And his feet shall stand in that day upon the mount of Olives, which is before Jerusalem on the east, and the mount of Olives shall cleave in the midst thereof toward the east and toward the west, and there shall be a very great valley; and half of the mountain shall remove toward the north, and half of it toward the south."},"BSB":{"text":"On that day His feet will stand on the Mount of Olives, east of Jerusalem, and the Mount of Olives will be split in two from east to west, forming a great valley, with half the mountain moving to the north and half to the south."}},"definableWords":["day","stand","Jerusalem","great"],"peopleInVerse":[]},"5":{"text":"And ye shall flee to the valley of the mountains; for the valley of the mountains shall reach unto Azal: yea, ye shall flee, like as ye fled from before the earthquake in the days of Uzziah king of Judah: and the LORD my God shall come, and all the saints with thee.","ref":"Zechariah 14:5","synthesized":"You will flee by My mountain valley, for it will extend to Azal. You will flee as you fled from the earthquake in the days of Uzziah king of Judah. Then the LORD my God will come, and all the holy ones with Him.","sources":{"KJV":{"text":"And ye shall flee to the valley of the mountains; for the valley of the mountains shall reach unto Azal: yea, ye shall flee, like as ye fled from before the earthquake in the days of Uzziah king of Judah: and the LORD my God shall come, and all the saints with thee."},"BSB":{"text":"You will flee by My mountain valley, for it will extend to Azal. You will flee as you fled from the earthquake in the days of Uzziah king of Judah. Then the LORD my God will come, and all the holy ones with Him."}},"definableWords":["days","king","Judah","LORD","God","holy"],"peopleInVerse":[]},"6":{"text":"And it shall come to pass in that day, that the light shall not be clear, nor dark:","ref":"Zechariah 14:6","synthesized":"On that day there will be no light, no cold or frost.","sources":{"KJV":{"text":"And it shall come to pass in that day, that the light shall not be clear, nor dark:"},"BSB":{"text":"On that day there will be no light, no cold or frost."}},"definableWords":["day","light","or"],"peopleInVerse":[]},"7":{"text":"But it shall be one day which shall be known to the LORD, not day, nor night: but it shall come to pass, that at evening time it shall be light.","ref":"Zechariah 14:7","synthesized":"It will be a day known only to the LORD, without day or night; but when evening comes, there will be light.","sources":{"KJV":{"text":"But it shall be one day which shall be known to the LORD, not day, nor night: but it shall come to pass, that at evening time it shall be light."},"BSB":{"text":"It will be a day known only to the LORD, without day or night; but when evening comes, there will be light."}},"definableWords":["day","LORD","or","night","light"],"peopleInVerse":[]},"8":{"text":"And it shall be in that day, that living waters shall go out from Jerusalem; half of them toward the former sea, and half of them toward the hinder sea: in summer and in winter shall it be.","ref":"Zechariah 14:8","synthesized":"And on that day living water will flow out from Jerusalem, half of it toward the Eastern Sea and the other half toward the Western Sea, in summer and winter alike.","sources":{"KJV":{"text":"And it shall be in that day, that living waters shall go out from Jerusalem; half of them toward the former sea, and half of them toward the hinder sea: in summer and in winter shall it be."},"BSB":{"text":"And on that day living water will flow out from Jerusalem, half of it toward the Eastern Sea and the other half toward the Western Sea, in summer and winter alike."}},"definableWords":["day","living","water","Jerusalem","sea"],"peopleInVerse":[]},"9":{"text":"And the LORD shall be king over all the earth: in that day shall there be one LORD, and his name one.","ref":"Zechariah 14:9","synthesized":"On that day the LORD will become King over all the earth—the LORD alone, and His name alone.","sources":{"KJV":{"text":"And the LORD shall be king over all the earth: in that day shall there be one LORD, and his name one."},"BSB":{"text":"On that day the LORD will become King over all the earth—the LORD alone, and His name alone."}},"definableWords":["day","LORD","King","earth","Lord","name"],"peopleInVerse":[]},"10":{"text":"All the land shall be turned as a plain from Geba to Rimmon south of Jerusalem: and it shall be lifted up, and inhabited in her place, from Benjamin’s gate unto the place of the first gate, unto the corner gate, and from the tower of Hananeel unto the king’s winepresses.","ref":"Zechariah 14:10","synthesized":"All the land from Geba to Rimmon south of Jerusalem will be turned into a plain, but Jerusalem will be raised up and will remain in her place, from the Benjamin Gate to the site of the First Gate to the Corner Gate, and from the Tower of Hananel to the royal winepresses.","sources":{"KJV":{"text":"All the land shall be turned as a plain from Geba to Rimmon south of Jerusalem: and it shall be lifted up, and inhabited in her place, from Benjamin’s gate unto the place of the first gate, unto the corner gate, and from the tower of Hananeel unto the king’s winepresses."},"BSB":{"text":"All the land from Geba to Rimmon south of Jerusalem will be turned into a plain, but Jerusalem will be raised up and will remain in her place, from the Benjamin Gate to the site of the First Gate to the Corner Gate, and from the Tower of Hananel to the royal winepresses."}},"definableWords":["land","Jerusalem","Benjamin"],"peopleInVerse":[]},"11":{"text":"And men shall dwell in it, and there shall be no more utter destruction; but Jerusalem shall be safely inhabited.","ref":"Zechariah 14:11","synthesized":"People will live there, and never again will there be an utter destruction. So Jerusalem will dwell securely.","sources":{"KJV":{"text":"And men shall dwell in it, and there shall be no more utter destruction; but Jerusalem shall be safely inhabited."},"BSB":{"text":"People will live there, and never again will there be an utter destruction. So Jerusalem will dwell securely."}},"definableWords":["people","live","Jerusalem"],"peopleInVerse":[]},"12":{"text":"And this shall be the plague wherewith the LORD will smite all the people that have fought against Jerusalem; Their flesh shall consume away while they stand upon their feet, and their eyes shall consume away in their holes, and their tongue shall consume away in their mouth.","ref":"Zechariah 14:12","synthesized":"And this will be the plague with which the LORD strikes all the peoples who have warred against Jerusalem: Their flesh will rot while they stand on their feet, their eyes will rot in their sockets, and their tongues will rot in their mouths.","sources":{"KJV":{"text":"And this shall be the plague wherewith the LORD will smite all the people that have fought against Jerusalem; Their flesh shall consume away while they stand upon their feet, and their eyes shall consume away in their holes, and their tongue shall consume away in their mouth."},"BSB":{"text":"And this will be the plague with which the LORD strikes all the peoples who have warred against Jerusalem: Their flesh will rot while they stand on their feet, their eyes will rot in their sockets, and their tongues will rot in their mouths."}},"definableWords":["LORD","Jerusalem","flesh","stand"],"peopleInVerse":[]},"13":{"text":"And it shall come to pass in that day, that a great tumult from the LORD shall be among them; and they shall lay hold every one on the hand of his neighbour, and his hand shall rise up against the hand of his neighbour.","ref":"Zechariah 14:13","synthesized":"On that day a great panic from the LORD will come upon them, so that each will seize the hand of another, and the hand of one will rise against the other.","sources":{"KJV":{"text":"And it shall come to pass in that day, that a great tumult from the LORD shall be among them; and they shall lay hold every one on the hand of his neighbour, and his hand shall rise up against the hand of his neighbour."},"BSB":{"text":"On that day a great panic from the LORD will come upon them, so that each will seize the hand of another, and the hand of one will rise against the other."}},"definableWords":["day","great","LORD","one"],"peopleInVerse":[]},"14":{"text":"And Judah also shall fight at Jerusalem; and the wealth of all the heathen round about shall be gathered together, gold, and silver, and apparel, in great abundance.","ref":"Zechariah 14:14","synthesized":"Judah will also fight at Jerusalem, and the wealth of all the surrounding nations will be collected—gold, silver, and apparel in great abundance.","sources":{"KJV":{"text":"And Judah also shall fight at Jerusalem; and the wealth of all the heathen round about shall be gathered together, gold, and silver, and apparel, in great abundance."},"BSB":{"text":"Judah will also fight at Jerusalem, and the wealth of all the surrounding nations will be collected—gold, silver, and apparel in great abundance."}},"definableWords":["Judah","fight","Jerusalem","nations","great"],"peopleInVerse":[]},"15":{"text":"And so shall be the plague of the horse, of the mule, of the camel, and of the ass, and of all the beasts that shall be in these tents, as this plague.","ref":"Zechariah 14:15","synthesized":"And a similar plague will strike the horses and mules, camels and donkeys, and all the animals in those camps.","sources":{"KJV":{"text":"And so shall be the plague of the horse, of the mule, of the camel, and of the ass, and of all the beasts that shall be in these tents, as this plague."},"BSB":{"text":"And a similar plague will strike the horses and mules, camels and donkeys, and all the animals in those camps."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"And it shall come to pass, that every one that is left of all the nations which came against Jerusalem shall even go up from year to year to worship the King, the LORD of hosts, and to keep the feast of tabernacles.","ref":"Zechariah 14:16","synthesized":"Then all the survivors from the nations that came against Jerusalem will go up year after year to worship the King, the LORD of Hosts, and to celebrate the Feast of Tabernacles.","sources":{"KJV":{"text":"And it shall come to pass, that every one that is left of all the nations which came against Jerusalem shall even go up from year to year to worship the King, the LORD of hosts, and to keep the feast of tabernacles."},"BSB":{"text":"Then all the survivors from the nations that came against Jerusalem will go up year after year to worship the King, the LORD of Hosts, and to celebrate the Feast of Tabernacles."}},"definableWords":["nations","Jerusalem","year","worship","King","LORD"],"peopleInVerse":[]},"17":{"text":"And it shall be, that whoso will not come up of all the families of the earth unto Jerusalem to worship the King, the LORD of hosts, even upon them shall be no rain.","ref":"Zechariah 14:17","synthesized":"And should any of the families of the earth not go up to Jerusalem to worship the King, the LORD of Hosts, then the rain will not fall on them.","sources":{"KJV":{"text":"And it shall be, that whoso will not come up of all the families of the earth unto Jerusalem to worship the King, the LORD of hosts, even upon them shall be no rain."},"BSB":{"text":"And should any of the families of the earth not go up to Jerusalem to worship the King, the LORD of Hosts, then the rain will not fall on them."}},"definableWords":["families","earth","Jerusalem","worship","King","LORD"],"peopleInVerse":[]},"18":{"text":"And if the family of Egypt go not up, and come not, that have no rain; there shall be the plague, wherewith the LORD will smite the heathen that come not up to keep the feast of tabernacles.","ref":"Zechariah 14:18","synthesized":"And if the people of Egypt will not go up and enter in, then the rain will not fall on them; this will be the plague with which the LORD strikes the nations who do not go up to celebrate the Feast of Tabernacles.","sources":{"KJV":{"text":"And if the family of Egypt go not up, and come not, that have no rain; there shall be the plague, wherewith the LORD will smite the heathen that come not up to keep the feast of tabernacles."},"BSB":{"text":"And if the people of Egypt will not go up and enter in, then the rain will not fall on them; this will be the plague with which the LORD strikes the nations who do not go up to celebrate the Feast of Tabernacles."}},"definableWords":["people","Egypt","LORD","nations"],"peopleInVerse":[]},"19":{"text":"This shall be the punishment of Egypt, and the punishment of all nations that come not up to keep the feast of tabernacles.","ref":"Zechariah 14:19","synthesized":"This will be the punishment of Egypt and of all the nations that do not go up to celebrate the Feast of Tabernacles.","sources":{"KJV":{"text":"This shall be the punishment of Egypt, and the punishment of all nations that come not up to keep the feast of tabernacles."},"BSB":{"text":"This will be the punishment of Egypt and of all the nations that do not go up to celebrate the Feast of Tabernacles."}},"definableWords":["Egypt","nations"],"peopleInVerse":[]},"20":{"text":"In that day shall there be upon the bells of the horses, HOLINESS UNTO THE LORD; and the pots in the LORD’s house shall be like the bowls before the altar.","ref":"Zechariah 14:20","synthesized":"On that day, HOLY TO THE LORD will be inscribed on the bells of the horses, and the cooking pots in the house of the LORD will be like the sprinkling bowls before the altar.","sources":{"KJV":{"text":"In that day shall there be upon the bells of the horses, HOLINESS UNTO THE LORD; and the pots in the LORD’s house shall be like the bowls before the altar."},"BSB":{"text":"On that day, HOLY TO THE LORD will be inscribed on the bells of the horses, and the cooking pots in the house of the LORD will be like the sprinkling bowls before the altar."}},"definableWords":["day","holy","LORD","house","Lord","altar"],"peopleInVerse":[]},"21":{"text":"Yea, every pot in Jerusalem and in Judah shall be holiness unto the LORD of hosts: and all they that sacrifice shall come and take of them, and seethe therein: and in that day there shall be no more the Canaanite in the house of the LORD of hosts.","ref":"Zechariah 14:21","synthesized":"Indeed, every pot in Jerusalem and Judah will be holy to the LORD of Hosts, and all who sacrifice will come and take some pots and cook in them. And on that day there will no longer be a Canaanite in the house of the LORD of Hosts.","sources":{"KJV":{"text":"Yea, every pot in Jerusalem and in Judah shall be holiness unto the LORD of hosts: and all they that sacrifice shall come and take of them, and seethe therein: and in that day there shall be no more the Canaanite in the house of the LORD of hosts."},"BSB":{"text":"Indeed, every pot in Jerusalem and Judah will be holy to the LORD of Hosts, and all who sacrifice will come and take some pots and cook in them. And on that day there will no longer be a Canaanite in the house of the LORD of Hosts."}},"definableWords":["Jerusalem","Judah","holy","LORD","sacrifice","day","house","Lord"],"peopleInVerse":[]}}}};